vector<int> buildFail(const string& p) {
    int m = p.size();
    vector<int> fail(m, 0);  // fail[0] = 0 always
    for (int i = 1; i < m; i++) {
        int j = fail[i - 1];
        while (j > 0 && p[i] != p[j])
            j = fail[j - 1];  // Fall back
        if (p[i] == p[j])
            j++;
        fail[i] = j;
    }
    return fail;
}
```

建構過程的不變量：`fail[i]` 代表 `p[0..i]` 最長真前後綴長度，每次用 `fail[j-1]` 跳回是因為 `p[0..j-1]` 的最長真前後綴已知。

```cpp
vector<int> kmpSearch(const string& text, const string& pattern) {
    string s = pattern + '#' + text;  // '#' must not appear in either string
    auto fail = buildFail(s);
    int m = pattern.size();
    vector<int> matches;
    for (int i = m + 1; i < (int)s.size(); i++)
        if (fail[i] == m)
            matches.push_back(i - 2 * m);  // Found at text[i-2m]
    return matches;
}
```

**另一種視角**：把 `pattern + '#' + text` 拼接後計算整個字串的 fail 陣列；在 text 部分，凡 `fail[i] == m` 的位置就是一個匹配點。分隔符 `'#'` 保證 fail 值不會跨越兩段。

template_code:
// KMP: find all occurrences of pattern in text
vector<int> kmpSearch(const string& text, const string& pattern) {
    if (pattern.empty())
        return {};
    string s = pattern + '#' + text;
    int n = s.size(), m = pattern.size();
    vector<int> fail(n, 0);
    for (int i = 1; i < n; i++) {
        int j = fail[i - 1];
        while (j > 0 && s[i] != s[j])
            j = fail[j - 1];
        if (s[i] == s[j])
            j++;
        fail[i] = j;
    }
    vector<int> result;
    for (int i = m + 1; i < n; i++)
        if (fail[i] == m)
            result.push_back(i - 2 * m);
    return result;
}

