// Polynomial string hashing (single hash)
struct Hash {
    static const long long kMod = 1e9 + 7, kBase = 131;
    vector<long long> h, pw;
    Hash(const string& s) : h(s.size() + 1, 0), pw(s.size() + 1, 1) {
        for (int i = 0; i < (int)s.size(); i++) {
            h[i + 1] = (h[i] * kBase + s[i]) % kMod;
            pw[i + 1] = pw[i] * kBase % kMod;
        }
    }
    long long get(int l, int r) {  // [l, r] 0-indexed inclusive
        return (h[r + 1] - h[l] * pw[r - l + 1] % kMod + kMod * 2) % kMod;
    }
};

