// K stops = K+1 edges: iterate exactly k+1 times
vector<long long> bellmanFordK(int src, int n, const vector<tuple<int, int, int>>& edges, int k) {
    vector<long long> dist(n, LLONG_MAX);
    dist[src] = 0;
    for (int iter = 0; iter <= k; iter++) {
        vector<long long> ndist = dist;  // Use previous round's values
        for (auto [u, v, w] : edges)
            if (dist[u] != LLONG_MAX)
                ndist[v] = min(ndist[v], dist[u] + w);
        dist = ndist;
    }
    return dist;
}
```
⚠️ 每輪必須用上一輪的 dist 副本（`ndist = dist`），否則一輪內可能做多跳鬆弛，超過層數限制。

```cpp
bool hasNegativeCycle(int n, const vector<vector<pair<int, int>>>& g) {
    vector<long long> dist(n, 0);
    vector<int> cnt(n, 0);  // Edge count to reach this node
    vector<bool> in_queue(n, true);
    queue<int> q;
    for (int i = 0; i < n; i++)
        q.push(i);  // Super source: start from all nodes
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        in_queue[u] = false;
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                cnt[v] = cnt[u] + 1;
                if (cnt[v] >= n)
                    return true;  // Negative cycle found
                if (!in_queue[v]) {
                    q.push(v);
                    in_queue[v] = true;
                }
            }
        }
    }
    return false;
}
```

template_code:
// Bellman-Ford: single source shortest path with negative edges
vector<long long> bellmanFord(int src, int n, const vector<tuple<int, int, int>>& edges) {
    vector<long long> dist(n, LLONG_MAX);
    dist[src] = 0;
    for (int i = 0; i < n - 1; i++) {
        bool updated = false;
        for (auto [u, v, w] : edges)
            if (dist[u] != LLONG_MAX && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                updated = true;
            }
        if (!updated)
            break;  // Early exit
    }
    return dist;
}

