template_code:
struct BinaryLiftingLca {
    int n = 0, kLog = 0, root = 1;
    vector<vector<int>> g, up;
    vector<int> dep;

    BinaryLiftingLca() = default;
    explicit BinaryLiftingLca(int n_) {
        init(n_);
    }

    void init(int n_) {
        n = n_;
        kLog = 1;
        while ((1LL << kLog) <= max(1, n))
            kLog++;
        g.assign(n + 1, {});
        up.assign(n + 1, vector<int>(kLog, 0));
        dep.assign(n + 1, 0);
    }

    void addEdge(int u, int v) {
        g[u].push_back(v);
        g[v].push_back(u);
    }

    void dfs(int v, int p) {
        up[v][0] = p;
        for (int k = 1; k < kLog; k++) {
            up[v][k] = up[up[v][k - 1]][k - 1];
        }
        for (int to : g[v]) {
            if (to == p)
                continue;
            dep[to] = dep[v] + 1;
            dfs(to, v);
        }
    }

    void build(int root_ = 1) {
        if (n == 0)
            return;
        root = root_;
        dep[root] = 0;
        dfs(root, root);
    }

    int lift(int v, int steps) const {
        for (int k = 0; k < kLog; k++) {
            if ((steps >> k) & 1)
                v = up[v][k];
        }
        return v;
    }

    int lca(int u, int v) const {
        if (dep[u] < dep[v])
            swap(u, v);
        u = lift(u, dep[u] - dep[v]);
        if (u == v)
            return u;
        for (int k = kLog - 1; k >= 0; k--) {
            if (up[u][k] != up[v][k]) {
                u = up[u][k];
                v = up[v][k];
            }
        }
        return up[u][0];
    }
};

