```cpp
const int kMaxN = 100005;
const int kLog = 17;

int up[kMaxN][kLog], dep[kMaxN];
long long dist[kMaxN];

int kthAncestor(int v, int k) {
    if (k > dep[v])
        return -1;
    for (int i = 0; i < kLog; i++) {
        if (k & (1 << i))
            v = up[v][i];
    }
    return v;
}

int lca(int u, int v) {
    if (dep[u] < dep[v])
        swap(u, v);
    int diff = dep[u] - dep[v];
    for (int k = 0; k < kLog; k++) {
        if (diff & (1 << k))
            u = up[u][k];
    }
    if (u == v)
        return u;
    for (int k = kLog - 1; k >= 0; k--) {
        if (up[u][k] != up[v][k]) {
            u = up[u][k];
            v = up[v][k];
        }
    }
    return up[u][0];
}

int treeDist(int u, int v) {
    int a = lca(u, v);
    return dep[u] + dep[v] - 2 * dep[a];
}

long long treeDistW(int u, int v) {
    int a = lca(u, v);
    return dist[u] + dist[v] - 2LL * dist[a];
}

bool onPath(int u, int v, int w) {
    return treeDist(u, w) + treeDist(w, v) == treeDist(u, v);
}

// k is 0-indexed from u toward v.
int pathNode(int u, int v, int k) {
    int a = lca(u, v);
    int up_len = dep[u] - dep[a];
    int total = dep[u] + dep[v] - 2 * dep[a];
    if (k < 0 || k > total)
        return -1;
    if (k <= up_len)
        return kthAncestor(u, k);
    return kthAncestor(v, total - k);
}
```
`treeDist` 算的是邊數，若題目要路徑上的節點數，記得再加 1。`pathNode` 這裡採 **0-indexed**：`k = 0` 代表 `u` 本身；若題目把起點算成第 1 個節點，先做 `--k` 再套公式即可。

