            dep[to] = dep[v] + 1;
            dist[to] = dist[v] + w;
            dfs(to, v);
        }
    }

    void build(int root_ = 1) {
        if (n == 0)
            return;
        root = root_;
        dep[root] = 0;
        dist[root] = 0;
        dfs(root, root);
    }

    int lift(int v, int steps) const {
        for (int k = 0; k < kLog; k++) {
            if ((steps >> k) & 1)
                v = up[v][k];
        }
        return v;
    }

    int lca(int u, int v) const {
        if (dep[u] < dep[v])
            swap(u, v);
        u = lift(u, dep[u] - dep[v]);
        if (u == v)
            return u;
        for (int k = kLog - 1; k >= 0; k--) {
            if (up[u][k] != up[v][k]) {
                u = up[u][k];
                v = up[v][k];
            }
        }
        return up[u][0];
    }

    int kthAncestor(int v, int k) const {
        if (k > dep[v])
            return -1;
        return lift(v, k);
    }

    int treeDist(int u, int v) const {
        int a = lca(u, v);
        return dep[u] + dep[v] - 2 * dep[a];
    }

    long long treeDistW(int u, int v) const {
        int a = lca(u, v);
        return dist[u] + dist[v] - 2LL * dist[a];
    }

    bool onPath(int u, int v, int w) const {
        return treeDist(u, w) + treeDist(w, v) == treeDist(u, v);
    }

    int pathNode(int u, int v, int k) const {
        int a = lca(u, v);
        int up_len = dep[u] - dep[a];
        int total = dep[u] + dep[v] - 2 * dep[a];
        if (k < 0 || k > total)
            return -1;
        if (k <= up_len)
            return kthAncestor(u, k);
        return kthAncestor(v, total - k);
    }
};

