```cpp
const int kMaxN = 100005;

int par[kMaxN], color[kMaxN];
vector<int> g[kMaxN];
vector<pair<int, int>> qs[kMaxN];
vector<int> ans;

int findSet(int x) {
    if (par[x] == x)
        return x;
    return par[x] = findSet(par[x]);
}

void dfs(int v, int p) {
    color[v] = 1;
    par[v] = v;
    for (int u : g[v]) {
        if (u == p)
            continue;
        dfs(u, v);
        par[findSet(u)] = v;
    }
    for (auto [u, qid] : qs[v]) {
        if (u == v)
            ans[qid] = v;
        else if (color[u] == 2)
            ans[qid] = findSet(u);
    }
    color[v] = 2;
}

struct Query {
    int u, v;
};

vector<int> solve(int root, int n, const vector<Query>& queries) {
    ans.assign((int)queries.size(), -1);
    for (int i = 1; i <= n; i++) {
        qs[i].clear();
        color[i] = 0;
        par[i] = i;
    }
    for (int i = 0; i < (int)queries.size(); i++) {
        int u = queries[i].u;
        int v = queries[i].v;
        qs[u].push_back({v, i});
        qs[v].push_back({u, i});
    }
    dfs(root, -1);
    return ans;
}

int main() {
    int n = 5;
    g[1] = {2, 3};
    g[2] = {1, 4, 5};
    g[3] = {1};
    g[4] = {2};
    g[5] = {2};

    vector<Query> queries = {{4, 5}, {3, 4}, {2, 2}};
    vector<int> res = solve(1, n, queries);

    for (int x : res) {
        cout << x << '\n';
    }
    return 0;
}
```
批量求解時要先把每個查詢 `(u, v)` 同時登記到 `qs[u]` 與 `qs[v]`，這樣第二個完成的端點才能拿到查詢編號並寫回答案。`u == v` 的自查詢在這裡直接回傳自己，避免被並查集一路合併到更高的祖先。

template_code:
struct TarjanOfflineLca {
    int n = 0;
    vector<vector<int>> g;
    vector<vector<pair<int, int>>> qs;
    vector<int> parent, color, answer;

    TarjanOfflineLca() = default;
    explicit TarjanOfflineLca(int n_) {
        init(n_);
    }

    void init(int n_) {
        n = n_;
        g.assign(n + 1, {});
        qs.assign(n + 1, {});
        parent.resize(n + 1);
        color.assign(n + 1, 0);
        iota(parent.begin(), parent.end(), 0);
        answer.clear();
    }

    void addEdge(int u, int v) {
        g[u].push_back(v);
        g[v].push_back(u);
    }

    int addQuery(int u, int v) {
        int id = (int)answer.size();
        answer.push_back(-1);
        qs[u].push_back({v, id});
        qs[v].push_back({u, id});
        return id;
    }

    int findSet(int x) {
        if (parent[x] == x)
            return x;
        return parent[x] = findSet(parent[x]);
    }

    void dfs(int v, int p) {
        color[v] = 1;
        parent[v] = v;
        for (int to : g[v]) {
            if (to == p)
                continue;
            dfs(to, v);
            parent[findSet(to)] = v;
        }
        for (auto [u, id] : qs[v]) {
            if (u == v)
                answer[id] = v;
            else if (color[u] == 2)
                answer[id] = findSet(u);
        }
        color[v] = 2;
    }

    vector<int> solve(int root = 1) {
        fill(color.begin(), color.end(), 0);
        iota(parent.begin(), parent.end(), 0);
        fill(answer.begin(), answer.end(), -1);
        dfs(root, -1);
        return answer;
    }
};

