    // Invariant: answer lies in [lo, hi]
    while (lo < hi) {
        long long mid = lo + (hi - lo) / 2;
        if (check(mid))
            hi = mid;  // mid is feasible, try smaller
        else
            lo = mid + 1;  // mid is not feasible, must go larger
    }
    return lo;  // lo == hi is the answer
}

// Binary search on answer — maximize: find largest x where check(x) is true
long long binarySearchMax(long long lo, long long hi) {
    while (lo < hi) {
        long long mid = lo + (hi - lo + 1) / 2;  // Upper-mid prevents infinite loop
        if (check(mid))
            lo = mid;  // mid is feasible, try larger
        else
            hi = mid - 1;  // mid is not feasible, must go smaller
