// TSP: find shortest Hamiltonian cycle through all n nodes
// dist[i][j] = distance from i to j (directed or undirected)
const long long kInf = 1e18;

long long tsp(int n, const vector<vector<long long>>& dist) {
    int full = 1 << n;
    // dp[mask][v] = min cost: visited set = mask, currently at v
    vector<vector<long long>> dp(full, vector<long long>(n, kInf));
    dp[1][0] = 0;  // Start at node 0, visited = {0}

    for (int mask = 1; mask < full; mask++) {
        for (int v = 0; v < n; v++) {
            if (!(mask & (1 << v)))
                continue;  // v must be in mask
            if (dp[mask][v] == kInf)
                continue;  // Unreachable state
            // Try moving to each unvisited node u
            for (int u = 0; u < n; u++) {
                if (mask & (1 << u))
                    continue;  // u already visited
                int new_mask = mask | (1 << u);
                long long new_cost = dp[mask][v] + dist[v][u];
                dp[new_mask][u] = min(dp[new_mask][u], new_cost);
            }
        }
    }

    // Return to start node 0 from each final node v
    long long ans = kInf;
    for (int v = 1; v < n; v++) {
        if (dp[full - 1][v] < kInf)
            ans = min(ans, dp[full - 1][v] + dist[v][0]);
    }
    return ans;  // kInf if no Hamiltonian cycle exists
}
```

枚舉所有 `2^n` 個狀態，每個狀態枚舉 n 個當前節點，每個節點再枚舉 n 個下一步，總複雜度 O(2^n × n²)。因為外層迴圈按照 `mask` 的大小遞增（小的 mask 先處理），所以不需要記憶化遞迴，直接迭代即可保證轉移順序正確。

```cpp
// Reconstruct the optimal Hamiltonian cycle path
const long long kInf = 1e18;

vector<int> tspPath(int n, const vector<vector<long long>>& dist) {
    int full = 1 << n;
    vector<vector<long long>> dp(full, vector<long long>(n, kInf));
    vector<vector<int>> prev(full, vector<int>(n, -1));  // Predecessor node
    dp[1][0] = 0;

    for (int mask = 1; mask < full; mask++) {
        for (int v = 0; v < n; v++) {
            if (!(mask & (1 << v)) || dp[mask][v] == kInf)
                continue;
            for (int u = 0; u < n; u++) {
                if (mask & (1 << u))
                    continue;
                int nm = mask | (1 << u);
                long long nc = dp[mask][v] + dist[v][u];
                if (nc < dp[nm][u]) {
                    dp[nm][u] = nc;
                    prev[nm][u] = v;  // Record predecessor
                }
            }
        }
    }

    // Find best last node before returning to 0
    int last = -1;
    long long best = kInf;
    for (int v = 1; v < n; v++) {
        long long cost = dp[full - 1][v] + dist[v][0];
        if (cost < best) {
            best = cost;
            last = v;
        }
    }

    // Trace back the path
    vector<int> path;
    int mask = full - 1, cur = last;
    while (cur != -1) {
        path.push_back(cur);
        int p = prev[mask][cur];
        mask ^= (1 << cur);  // Remove cur from mask
        cur = p;
    }
    reverse(path.begin(), path.end());
    path.push_back(0);  // Return to start
    return path;
}
```

路徑重建的關鍵是額外維護 `prev[mask][v]` 記錄每個狀態的前驅節點，反向追蹤時每步移除 `mask` 中的當前節點 `cur`（`mask ^= 1<<cur`），直到 `prev = -1`（回到起點）。空間需求因此增加一個 O(2^n × n) 的整數陣列。

