```cpp
// Twice the SIGNED area of polygon p[0..n-1].
// Positive if vertices are in CCW order, negative if CW.
long long area2(const vector<Point>& p) {
    long long s = 0;
    int n = p.size();
    for (int i = 0; i < n; i++) {
        Point a = p[i], b = p[(i + 1) % n];
        s += cross(a, b);  // a.x*b.y - a.y*b.x
    }
    return s;  // real area = abs(s) / 2.0
}
```

