// Returns hull vertices in CCW order. Uses <= 0 to DROP collinear
// points on edges; use < 0 to KEEP them.
vector<Point> convexHull(vector<Point> p) {
    sort(p.begin(), p.end(), [](Point a, Point b) { return a.x != b.x ? a.x < b.x : a.y < b.y; });
    p.erase(unique(p.begin(), p.end()), p.end());
    int n = p.size(), k = 0;
    if (n < 3)
        return p;
    vector<Point> h(2 * n);
    for (int i = 0; i < n; i++) {  // lower hull
        while (k >= 2 && cross(h[k - 1] - h[k - 2], p[i] - h[k - 2]) <= 0)
            k--;
        h[k++] = p[i];
    }
    for (int i = n - 2, t = k + 1; i >= 0; i--) {  // upper hull
        while (k >= t && cross(h[k - 1] - h[k - 2], p[i] - h[k - 2]) <= 0)
            k--;
        h[k++] = p[i];
    }
    h.resize(k - 1);  // last point == first, drop it
    return h;
}
```

`t = k + 1` 確保建上凸包時不會把下凸包的起點彈掉。最後一個點與第一個點重合，故 `resize(k - 1)`。

