bool segInter(Point a, Point b, Point c, Point d) {
    long long d1 = cross(b - a, c - a), d2 = cross(b - a, d - a);
    long long d3 = cross(d - c, a - c), d4 = cross(d - c, b - c);
    if (sgn(d1) * sgn(d2) < 0 && sgn(d3) * sgn(d4) < 0)
        return true;  // proper
    if (d1 == 0 && onSegment(a, b, c))
        return true;  // collinear endpoint cases
    if (d2 == 0 && onSegment(a, b, d))
        return true;
