long long dist2(Point a, Point b) {
    long long dx = a.x - b.x, dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// Sort by x first, then call rec(0, n). a[] gets reordered by y in-place.
long long rec(int l, int r, vector<Point>& a) {
    if (r - l <= 3) {  // base case: brute force + sort by y
        long long best = LLONG_MAX;
        for (int i = l; i < r; i++)
            for (int j = i + 1; j < r; j++)
                best = min(best, dist2(a[i], a[j]));
        sort(a.begin() + l, a.begin() + r, [](Point p, Point q) { return p.y < q.y; });
        return best;
    }
    int m = (l + r) / 2;
    long long midx = a[m].x;
    long long d = min(rec(l, m, a), rec(m, r, a));
    inplace_merge(a.begin() + l, a.begin() + m, a.begin() + r,
                  [](Point p, Point q) { return p.y < q.y; });  // now [l, r) sorted by y
    vector<Point> strip;
    for (int i = l; i < r; i++)
        if ((a[i].x - midx) * (a[i].x - midx) < d)
            strip.push_back(a[i]);
    for (int i = 0; i < (int)strip.size(); i++)
        for (int j = i + 1;
             j < (int)strip.size() && (strip[j].y - strip[i].y) * (strip[j].y - strip[i].y) < d;
             j++)
            d = min(d, dist2(strip[i], strip[j]));
    return d;
}
```

用 `inplace_merge` 在回溯時順手把區間依 y 合併好，避免每層重新排序，維持 O(n log n)。內層 j 迴圈一旦 y 差距平方 `>= d` 就 break，這是「每點只比常數個」的關鍵。

