    set<pair<long long, long long>> active;  // (y, x)
    int j = 0;
    for (int i = 0; i < (int)pts.size(); i++) {
        while (j < i && (pts[i].x - pts[j].x) * (pts[i].x - pts[j].x) >= best) {
            active.erase({pts[j].y, pts[j].x});
            j++;
        }
        long long d = (long long)ceil(sqrt((double)best)) + 1;
        auto lo = active.lower_bound({pts[i].y - d, LLONG_MIN});
        auto hi = active.upper_bound({pts[i].y + d, LLONG_MAX});
        for (auto it = lo; it != hi; ++it)
            best = min(best, dist2(Point{it->second, it->first}, pts[i]));
        active.insert({pts[i].y, pts[i].x});
    }
    return best;
}
```

掃描線版好寫好記：用 `set` 維護 x 在當前最近距離內的「活躍點」，每個新點只查 y 介於 `[y-d, y+d]` 的少數點。實作較短，常被用來替代分治。

template_code:
struct Point {
    long long x, y;
};
long long dist2(Point a, Point b) {
    long long dx = a.x - b.x, dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// a[] must be sorted by x before the first call: rec(0, a.size(), a).
// Reorders a[] by y in place. Returns SQUARED closest distance.
long long rec(int l, int r, vector<Point>& a) {
    if (r - l <= 3) {
        long long best = LLONG_MAX;
        for (int i = l; i < r; i++)
            for (int j = i + 1; j < r; j++)
                best = min(best, dist2(a[i], a[j]));
        sort(a.begin() + l, a.begin() + r, [](Point p, Point q) { return p.y < q.y; });
        return best;
    }
    int m = (l + r) / 2;
    long long midx = a[m].x;
    long long d = min(rec(l, m, a), rec(m, r, a));
    inplace_merge(a.begin() + l, a.begin() + m, a.begin() + r,
                  [](Point p, Point q) { return p.y < q.y; });
    vector<Point> strip;
    for (int i = l; i < r; i++)
        if ((a[i].x - midx) * (a[i].x - midx) < d)
            strip.push_back(a[i]);
    for (int i = 0; i < (int)strip.size(); i++)
        for (int j = i + 1;
             j < (int)strip.size() && (strip[j].y - strip[i].y) * (strip[j].y - strip[i].y) < d;
             j++)
            d = min(d, dist2(strip[i], strip[j]));
    return d;
}

long long closestPair(vector<Point> pts) {
    sort(pts.begin(), pts.end(),
         [](Point a, Point b) { return a.x != b.x ? a.x < b.x : a.y < b.y; });
    return rec(0, pts.size(), pts);
}

