long long maxSubarray(vector<int>& a) {
    long long ans = a[0], cur = a[0];
    for (int i = 1; i < (int)a.size(); i++) {
        cur = max((long long)a[i], cur + a[i]);  // Restart if prefix is negative
        ans = max(ans, cur);
    }
    return ans;
}
