// Returns length of Longest Strictly Increasing Subsequence
int lis(vector<int>& a) {
    vector<int> tails;  // tails[i] = smallest tail of IS of length i+1
    for (int x : a) {
        auto it = lower_bound(tails.begin(), tails.end(), x);
        if (it == tails.end())
            tails.push_back(x);
        else
            *it = x;
    }
    return (int)tails.size();
