// Reconstruct one valid LIS sequence
vector<int> lisRecover(vector<int>& a) {
    int n = a.size();
    vector<int> tails, pos(n), par(n, -1);
    vector<int> tail_pos;  // Index in a[] corresponding to each tail
    for (int i = 0; i < n; i++) {
        auto it = lower_bound(tails.begin(), tails.end(), a[i]);
        int k = it - tails.begin();
        if (it == tails.end()) {
            tails.push_back(a[i]);
            tail_pos.push_back(i);
        } else {
            tails[k] = a[i];
            tail_pos[k] = i;
        }
        pos[i] = k;
        if (k > 0)
            par[i] = tail_pos[k - 1];
    }
    vector<int> res;
    for (int cur = tail_pos.back(); cur != -1; cur = par[cur])
        res.push_back(a[cur]);
    reverse(res.begin(), res.end());
    return res;
}

