// 0/1 Knapsack: each item used at most once
// Iterate capacity in reverse to prevent reuse
int knapsack01(int cap, vector<int>& w, vector<int>& v) {
    int n = w.size();
    vector<int> dp(cap + 1, 0);
    for (int i = 0; i < n; i++)
        for (int j = cap; j >= w[i]; j--)  // Reverse: no reuse
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
    return dp[cap];
}

// Unbounded Knapsack: each item used unlimited times
// Iterate capacity forward to allow reuse
int knapsackUnbounded(int cap, vector<int>& w, vector<int>& v) {
    int n = w.size();
    vector<int> dp(cap + 1, 0);
    for (int i = 0; i < n; i++)
        for (int j = w[i]; j <= cap; j++)  // Forward: allow reuse
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
    return dp[cap];
}
```
兩者唯一差異是內層迴圈方向：**逆序**保證每件物品至多選一次（更新時 `dp[j-w[i]]` 尚未包含第 i 件）；**正序**允許重複選（`dp[j-w[i]]` 已更新過，代表已可能再選一次第 i 件）。記憶口訣：0/1 逆，完全正。

```cpp
// Multiple Knapsack via binary grouping
// Each item i: weight w[i], value v[i], count c[i]
int knapsackMultiple(int cap, vector<int>& w, vector<int>& v, vector<int>& c) {
    // Decompose each item into groups of sizes 1, 2, 4, ..., remainder
    vector<int> gw, gv;
    for (int i = 0; i < (int)w.size(); i++) {
        int rem = c[i];
        for (int k = 1; rem > 0; k <<= 1) {
            int take = min(k, rem);
            gw.push_back(take * w[i]);
            gv.push_back(take * v[i]);
            rem -= take;
        }
    }
    // Standard 0/1 knapsack on grouped items
    vector<int> dp(cap + 1, 0);
    for (int i = 0; i < (int)gw.size(); i++)
        for (int j = cap; j >= gw[i]; j--)
            dp[j] = max(dp[j], dp[j - gw[i]] + gv[i]);
    return dp[cap];
}
```
二進位分組的正確性：任意 `0 <= x <= c` 都能以 `{1, 2, 4, …, 2^k, r}` 的子集之和表示，因此不會遺漏任何合法選取數量，同時組數從 O(C) 壓縮到 O(log C)，顯著減少虛擬物品總數。

