// Stone merging: n piles in a row, minimize total merge cost
// Cost of any merge equals the total weight of the merged piles
int stoneMerge(vector<int>& stones) {
    int n = stones.size();
    vector<int> pre(n + 1, 0);  // Prefix sum
    for (int i = 0; i < n; i++)
        pre[i + 1] = pre[i] + stones[i];

    // dp[l][r] = min cost to merge stones[l..r] into one pile
    vector<vector<int>> dp(n, vector<int>(n, 0));
    for (int len = 2; len <= n; len++) {
        for (int l = 0; l + len - 1 < n; l++) {
            int r = l + len - 1;
            dp[l][r] = INT_MAX;
            int cost = pre[r + 1] - pre[l];  // Total weight of [l..r]
            for (int k = l; k < r; k++)      // Split: left=[l, k], right=[k+1, r]
                dp[l][r] = min(dp[l][r], dp[l][k] + dp[k + 1][r] + cost);
        }
    }
    return dp[0][n - 1];
}
```
