// Number triangle: min cost path from top to bottom row
// Move from (r, c) to (r+1, c) or (r+1, c+1)
vector<vector<int>> tri;
vector<vector<int>> memo;

int minPath(int r, int c) {
    if (r == (int)tri.size() - 1)
        return tri[r][c];  // Base case: last row
    if (memo[r][c] != -1)
        return memo[r][c];  // Cache hit
    int down = minPath(r + 1, c);
    int down_right = minPath(r + 1, c + 1);
    return memo[r][c] = tri[r][c] + min(down, down_right);
}

int solve(int n) {
    memo.assign(n, vector<int>(n, -1));
    return minPath(0, 0);
}
