    if (n <= 0)
        return 1;  // Empty board: 1 way
    if (n == 1)
        return 1;
    auto it = memo.find(n);
    if (it != memo.end())
        return it->second;  // Cache hit
    // Place vertical tile or two horizontal tiles
    return memo[n] = tile(n - 1) + tile(n - 2);
