struct DsuRank {
    vector<int> par, rnk;

    explicit DsuRank(int n) : par(n + 1), rnk(n + 1, 0) {
        iota(par.begin(), par.end(), 0);
    }

    int findRoot(int x) {
        if (par[x] == x)
            return x;
        return par[x] = findRoot(par[x]);
    }

    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b)
            return false;
        if (rnk[a] < rnk[b])
            swap(a, b);
        par[b] = a;
        if (rnk[a] == rnk[b])
            rnk[a]++;
        return true;
    }
};

struct DsuSize {
    vector<int> par, sz;

    explicit DsuSize(int n) : par(n + 1), sz(n + 1, 1) {
        iota(par.begin(), par.end(), 0);
    }

    int findRoot(int x) {
        if (par[x] == x)
            return x;
        return par[x] = findRoot(par[x]);
    }

    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b)
            return false;
        if (sz[a] < sz[b])
            swap(a, b);
        par[b] = a;
        sz[a] += sz[b];
        return true;
    }
};
```

