```cpp
struct AdditiveWeightedDsu {
    vector<int> par, sz;
    vector<long long> d;  // val[x] - val[parent[x]]

    AdditiveWeightedDsu() = default;
    explicit AdditiveWeightedDsu(int n) {
        init(n);
    }

    void init(int n) {
        par.resize(n + 1);
        iota(par.begin(), par.end(), 0);
        sz.assign(n + 1, 1);
        d.assign(n + 1, 0);
    }

    int findRoot(int x) {
        if (par[x] == x)
            return x;
        int p = par[x];
        int root = findRoot(p);
        d[x] += d[p];
        return par[x] = root;
    }

    bool unite(int x, int y, long long w) {  // val[x] - val[y] = w
        int rx = findRoot(x);
        int ry = findRoot(y);
        long long dx = d[x];
        long long dy = d[y];
        if (rx == ry)
            return dx - dy == w;

        if (sz[rx] < sz[ry]) {
            par[rx] = ry;
            d[rx] = w + dy - dx;  // val[rx] - val[ry]
            sz[ry] += sz[rx];
        } else {
            par[ry] = rx;
            d[ry] = dx - dy - w;  // val[ry] - val[rx]
            sz[rx] += sz[ry];
        }
        return true;
    }

    long long query(int x, int y) {
        if (findRoot(x) != findRoot(y))
            return LLONG_MIN;
        return d[x] - d[y];
    }
};
```

這裡最容易錯的是讀值時機：一定要先做 `find(x)`、`find(y)`，再讀 `d[x]`、`d[y]`，因為壓縮後它們才是相對根的差值。若兩點本來就在同一集合，`unite` 也不能直接略過，而要檢查 `dx - dy` 是否真的等於新約束 `w`。

若題目關係是比例而不是差值，就把路徑合成從加法改成乘法：

