        iota(par.begin(), par.end(), 0);
        sz.assign(n + 1, 1);
        dm.assign(n + 1, 1.0);
    }

    int findM(int x) {
        if (par[x] == x)
            return x;
        int p = par[x];
        int root = findM(p);
        dm[x] *= dm[p];
        return par[x] = root;
    }

    bool uniteM(int x, int y, double r) {  // val[x] / val[y] = r
        int rx = findM(x);
        int ry = findM(y);
        double dx = dm[x];
        double dy = dm[y];
        if (rx == ry) {
            if (fabs(dy) <= kEps)
                return false;
            return fabs(dx / dy - r) <= kEps;
        }
        if (fabs(dx) <= kEps || fabs(dy) <= kEps || fabs(r) <= kEps)
            return false;

        if (sz[rx] < sz[ry]) {
            par[rx] = ry;
            dm[rx] = r * dy / dx;  // val[rx] / val[ry]
            sz[ry] += sz[rx];
        } else {
            par[ry] = rx;
            dm[ry] = dx / (dy * r);  // val[ry] / val[rx]
            sz[rx] += sz[ry];
        }
        return true;
    }

    double queryM(int x, int y) {
        int rx = findM(x);
        int ry = findM(y);
        if (rx != ry || fabs(dm[y]) <= kEps) {
            return numeric_limits<double>::quiet_NaN();
        }
        return dm[x] / dm[y];
    }
};
```

乘法型的 `findM` 是把整條路徑上的比例一路相乘，因此 `dm[x]` 最後會變成 `x` 相對根的比值。因為使用浮點數，檢查同集合約束時要搭配 `EPS`；另外公式裡有除法，若題目可能出現 0 或極小值，也必須先做防呆。

template_code:
struct WeightedDsu {
    vector<int> par, sz;
    vector<long long> d;

    WeightedDsu() = default;
    explicit WeightedDsu(int n) {
        init(n);
    }

    void init(int n) {
        par.resize(n + 1);
        iota(par.begin(), par.end(), 0);
        sz.assign(n + 1, 1);
        d.assign(n + 1, 0);
    }

    int findRoot(int x) {
        if (par[x] == x)
            return x;
        int p = par[x];
        int root = findRoot(p);
        d[x] += d[p];
        return par[x] = root;
    }

    bool unite(int x, int y, long long w) {
        int rx = findRoot(x);
        int ry = findRoot(y);
        long long dx = d[x];
        long long dy = d[y];
        if (rx == ry)
            return dx - dy == w;

        if (sz[rx] < sz[ry]) {
            par[rx] = ry;
            d[rx] = w + dy - dx;
            sz[ry] += sz[rx];
        } else {
            par[ry] = rx;
            d[ry] = dx - dy - w;
            sz[rx] += sz[ry];
        }
        return true;
    }

    long long query(int x, int y) {
        if (findRoot(x) != findRoot(y))
            return LLONG_MIN;
        return d[x] - d[y];
    }
};

