        b = findRoot(b);
        if (a == b)
            return false;
        if (sz[a] < sz[b])
            swap(a, b);
        par[b] = a;
        sz[a] += sz[b];
        return true;
    }

    bool same(int a, int b) {
        return findRoot(a) == findRoot(b);
    }
