struct Query {
    int op, x, y;
};

int foodChain(int n, const vector<Query>& queries) {
    Dsu dsu;
    dsu.init(3 * (n + 1));
    int lies = 0;

    for (auto [op, x, y] : queries) {
        if (x < 1 || x > n || y < 1 || y > n) {
            lies++;
            continue;
        }

        if (op == 1) {
            if (dsu.same(x, y + n) || dsu.same(x, y + 2 * n)) {
                lies++;
                continue;
            }
            dsu.unite(x, y);
            dsu.unite(x + n, y + n);
            dsu.unite(x + 2 * n, y + 2 * n);
        } else if (op == 2) {
            if (x == y || dsu.same(x, y) || dsu.same(x, y + n)) {
                lies++;
                continue;
            }
            dsu.unite(x + n, y);
            dsu.unite(x + 2 * n, y + n);
            dsu.unite(x, y + 2 * n);
        }
    }
    return lies;
}
