// Standard BFS: single source shortest distance on unweighted graph
vector<int> bfs(int src, int n, const vector<vector<int>>& g) {
    vector<int> dist(n, -1);
    queue<int> q;
    dist[src] = 0;
    q.push(src);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : g[u])
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
    }
    return dist;
}

// Multi-source BFS: distance to nearest source for each node
vector<int> multiBfs(const vector<int>& sources, int n, const vector<vector<int>>& g) {
    vector<int> dist(n, -1);
    queue<int> q;
    for (int s : sources) {
        dist[s] = 0;
        q.push(s);
    }  // All sources enqueued at once
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : g[u])
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
    }
    return dist;
}
```
多源 BFS 的關鍵在於把所有源點**同時**放入佇列並設距離為 0，此後展開與單源完全相同。等效於加入一個超級源點 S，對每個源點 s 連一條邊權為 0 的邊 S→s。

```cpp
// 0-1 BFS: edges have weight 0 or 1 only
// g[u] = {(v, w)} where w is 0 or 1
vector<int> bfs01(int src, int n, const vector<vector<pair<int, int>>>& g) {
    vector<int> dist(n, INT_MAX);
    deque<int> dq;
    dist[src] = 0;
    dq.push_back(src);
    while (!dq.empty()) {
        int u = dq.front();
        dq.pop_front();
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                if (w == 0)
                    dq.push_front(v);  // Same layer: push to front
                else
                    dq.push_back(v);  // Next layer:  push to back
            }
        }
    }
    return dist;
}
```
邊權 0 的鄰居從**前端**插入確保先被處理（當前層）；邊權 1 的鄰居從**後端**插入（下一層）。deque 中元素的距離始終非遞減，等效於最小堆但每次操作為 O(1)，整體 O(n + m)。

