void solve(int n, const vector<vector<int>>& g) {
    tin.assign(n, 0);
    tout.assign(n, 0);
    visited.assign(n, false);
    timer_count = 0;
    for (int i = 0; i < n; i++)
        if (!visited[i])
            dfs(i, -1, g);
}
