// Iterative DFS to avoid stack overflow on long-chain graphs
int countComponents(int n, const vector<vector<int>>& g) {
    vector<bool> visited(n, false);
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (visited[i])
            continue;
        count++;  // New connected component
        stack<int> st;
        st.push(i);
        visited[i] = true;
        while (!st.empty()) {
            int u = st.top();
            st.pop();
            for (int v : g[u])
                if (!visited[v]) {
                    visited[v] = true;
                    st.push(v);
                }
        }
    }
    return count;
}
```
迭代 DFS 用顯式 `stack` 替代系統遞迴堆疊，避免深鏈圖（如長鏈 n = 10⁵）導致的堆疊溢出。每次進入外層 `for` 迴圈發現未訪問節點，即開啟一個新的連通分量。

