// BFS bipartite check; color[] stores 0/1 partition, -1 if uncolored
// Handles disconnected graphs by iterating over all nodes
bool isBipartite(int n, const vector<vector<int>>& g, vector<int>& color) {
    color.assign(n, -1);
    for (int start = 0; start < n; start++) {
        if (color[start] != -1)
            continue;  // Already colored
        queue<int> q;
        q.push(start);
        color[start] = 0;
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int v : g[u]) {
                if (color[v] == -1) {
                    color[v] = 1 - color[u];  // Assign opposite color
                    q.push(v);
                } else if (color[v] == color[u]) {
                    return false;  // Same color: odd cycle found
                }
            }
        }
    }
    return true;
}
