    side.assign(n, -1);
    for (int i = 0; i < n; i++)
        if (side[i] == -1 && !dfsBipartite(i, 0, g))
            return {{}, {}};
    vector<int> left, right;
    for (int i = 0; i < n; i++)
        (side[i] == 0 ? left : right).push_back(i);
    return {left, right};
}
