const int kMaxN = 200000;
int heap_arr[kMaxN + 5];
int heap_size = 0;

void siftUp(int idx) {
    while (idx > 1 && heap_arr[idx] > heap_arr[idx / 2]) {
        swap(heap_arr[idx], heap_arr[idx / 2]);
        idx /= 2;
    }
}

void siftDown(int idx) {
    while (true) {
        int left = idx * 2;
        int right = left + 1;
        int largest = idx;
        if (left <= heap_size && heap_arr[left] > heap_arr[largest])
            largest = left;
        if (right <= heap_size && heap_arr[right] > heap_arr[largest])
            largest = right;
        if (largest == idx)
            break;
        swap(heap_arr[idx], heap_arr[largest]);
        idx = largest;
    }
}

void push(int val) {
    heap_arr[++heap_size] = val;
    siftUp(heap_size);
}

int top() {
    return heap_arr[1];
}

void pop() {
    swap(heap_arr[1], heap_arr[heap_size]);
    heap_size--;
    if (heap_size > 0)
        siftDown(1);
}
```
`push` 先把新元素放到陣列尾端，再靠 `siftUp` 沿著父鏈往上修正；`pop` 則把根與尾端交換後縮小堆，再用 `siftDown` 往下和較大的孩子交換。因為兩種操作都只會沿著一條根到葉或葉到根的路徑移動，所以交換次數最多就是樹高。

