template_code:
struct BinaryMaxHeap {
    vector<int> heap;

    BinaryMaxHeap() : heap(1, 0) {}

    explicit BinaryMaxHeap(const vector<int>& a) : heap(1, 0) {
        buildHeap(a);
    }

    int size() const {
        return (int)heap.size() - 1;
    }

    bool empty() const {
        return size() == 0;
    }

    void siftUp(int idx) {
        while (idx > 1 && heap[idx] > heap[idx / 2]) {
            swap(heap[idx], heap[idx / 2]);
            idx /= 2;
        }
    }

    void siftDown(int idx) {
        int n = size();
        while (true) {
            int left = idx * 2;
            int right = left + 1;
            int largest = idx;
            if (left <= n && heap[left] > heap[largest])
                largest = left;
            if (right <= n && heap[right] > heap[largest])
                largest = right;
            if (largest == idx)
                break;
            swap(heap[idx], heap[largest]);
            idx = largest;
        }
    }

    void push(int val) {
        heap.push_back(val);
        siftUp(size());
    }

    int top() const {
        return heap[1];
    }

    void pop() {
        if (empty())
            return;
        int n = size();
        swap(heap[1], heap[n]);
        heap.pop_back();
        if (!empty())
            siftDown(1);
    }

    void buildHeap(const vector<int>& a) {
        heap.assign(1, 0);
        heap.insert(heap.end(), a.begin(), a.end());
        for (int i = size() / 2; i >= 1; --i) {
            siftDown(i);
        }
    }
};

