        auto it = delayed.find(x);
        return it != delayed.end() && it->second > 0;
    }

    void pruneSmall() {
        while (!small.empty() && isDelayed(small.top())) {
            int x = small.top();
            auto it = delayed.find(x);
            if (--it->second == 0)
                delayed.erase(it);
            small.pop();
        }
    }

    void pruneLarge() {
        while (!large.empty() && isDelayed(large.top())) {
            int x = large.top();
            auto it = delayed.find(x);
            if (--it->second == 0)
                delayed.erase(it);
            large.pop();
        }
    }

    void rebalance() {
        if (small_size > large_size + 1) {
            large.push(small.top());
            small.pop();
            small_size--;
            large_size++;
            pruneSmall();
        } else if (small_size < large_size) {
            small.push(large.top());
            large.pop();
            small_size++;
            large_size--;
            pruneLarge();
        }
