// Solve ax ≡ c (mod m).
// Returns smallest non-negative solution, or -1 if no solution exists.
long long solveCongruence(long long a, long long c, long long m) {
    long long x, y;
    long long g = exgcd(a, m, x, y);
    if (c % g != 0)
        return -1;          // No solution: g does not divide c
    long long mod = m / g;  // Solution period
    // x is a particular solution to a*x + m*y = g; scale by c/g
    return ((__int128)x * (c / g) % mod + mod) % mod;
}
```
