// Returns x mod (product of all m[i]); assumes product fits in long long
long long crtCoprime(const vector<long long>& r, const vector<long long>& m) {
    long long M = 1;
    for (long long mi : m)
        M *= mi;  // Total modulus
    long long x = 0;
    for (int i = 0; i < (int)r.size(); i++) {
        long long Mi = M / m[i];  // Product of all moduli except m[i]
        long long xi, yi;
