// Merge x ≡ r1 (mod m1) and x ≡ r2 (mod m2).
// Returns {r, lcm(m1, m2)} or {-1, -1} if incompatible.
pair<long long, long long> crtMerge(long long r1, long long m1, long long r2, long long m2) {
    long long x, y;
    long long g = exgcd(m1, m2, x, y);  // m1*x + m2*y = g
    if ((r2 - r1) % g != 0)
        return {-1, -1};          // Incompatible
    long long lcm = m1 / g * m2;  // Divide first to reduce overflow
    // t = (r2 - r1) / g * x  mod (m2/g)
    long long t = (__int128)(r2 - r1) / g * x % (m2 / g);
    long long r = (r1 + (__int128)m1 * t % lcm + lcm) % lcm;
    return {r, lcm};
}

// Solve a system of congruences (moduli need not be coprime)
