    long long cr = r[0], cm = m[0];
    for (int i = 1; i < (int)r.size(); i++) {
        auto [nr, nm] = crtMerge(cr, cm, r[i], m[i]);
        if (nr == -1)
            return {-1, -1};  // No solution
        cr = nr;
        cm = nm;
    }
    return {cr, cm};  // x ≡ cr (mod cm)
