// Kruskal MST: sort edges by weight, then greedily add with Dsu
struct Dsu {
    vector<int> p, r;
    Dsu(int n) : p(n), r(n, 0) {
        iota(p.begin(), p.end(), 0);
    }
    int findRoot(int x) {
        return p[x] == x ? x : p[x] = findRoot(p[x]);
    }
    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b)
            return false;
        if (r[a] < r[b])
            swap(a, b);
        p[b] = a;
        if (r[a] == r[b])
            r[a]++;
        return true;
    }
};
// edges = vector of {weight, u, v}; nodes are 0-indexed
long long kruskal(int n, vector<tuple<int, int, int>> edges) {
    sort(edges.begin(), edges.end());
    Dsu dsu(n);
    long long tot = 0;
    int cnt = 0;
    for (auto [w, u, v] : edges)
        if (dsu.unite(u, v)) {
            tot += w;
            if (++cnt == n - 1)
                break;
        }
    return cnt == n - 1 ? tot : -1LL;  // -1 if disconnected
}

