// Prim's MST with priority_queue (heap-optimized, for sparse graphs)
long long prim(int src, int n, const vector<vector<pair<int, int>>>& g) {
    const long long kInf = 1e18;
    vector<long long> key(n, kInf);  // Min edge weight to connect v to current MST
    vector<bool> in_mst(n, false);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    key[src] = 0;
    pq.push({0, src});
    long long total = 0;
    int cnt = 0;
    while (!pq.empty()) {
