// O(V^2) Prim for dense graphs using adjacency matrix
// adj[i][j] = edge weight, kInf if no direct edge
long long primDense(int n, const vector<vector<long long>>& adj) {
    const long long kInf = 1e18;
    vector<long long> key(n, kInf);
    vector<bool> in_mst(n, false);
    key[0] = 0;  // Start from node 0
    long long total = 0;
    for (int iter = 0; iter < n; iter++) {
        // Find minimum key vertex not yet in MST (linear scan)
        int u = -1;
        for (int v = 0; v < n; v++)
            if (!in_mst[v] && (u == -1 || key[v] < key[u]))
                u = v;
        if (key[u] == kInf)
            return -1;  // Graph is disconnected
        in_mst[u] = true;
        total += key[u];
        // Update keys for all neighbors of u
        for (int v = 0; v < n; v++)
            if (!in_mst[v] && adj[u][v] < key[v])
                key[v] = adj[u][v];
    }
    return total;
}
