const int kMod = 1'000'000'007;

long long sumSubarrayMins(const vector<int>& a) {
    int n = (int)a.size();
    vector<long long> left(n), right(n);
    stack<int> st;

    for (int i = 0; i < n; i++) {
        while (!st.empty() && a[st.top()] >= a[i])
            st.pop();
        int prev = st.empty() ? -1 : st.top();
        left[i] = i - prev;
        st.push(i);
    }

    while (!st.empty())
        st.pop();

    for (int i = n - 1; i >= 0; i--) {
        while (!st.empty() && a[st.top()] > a[i])
            st.pop();
        int next = st.empty() ? n : st.top();
        right[i] = next - i;
        st.push(i);
    }

    long long ans = 0;
    for (int i = 0; i < n; i++) {
        long long contrib = 1LL * a[i] * left[i] % kMod * right[i] % kMod;
        ans = (ans + contrib) % kMod;
    }
    return ans;
}
```
這裡的 `left[i]` 與 `right[i]` 不是邊界下標，而是「可以往左／往右延伸的選擇數」。左邊找**嚴格更小**、右邊找**小於等於**，會把含有多個相同最小值的子陣列唯一地分配給其中一個位置，避免重複計數。把每個 `a[i]` 的貢獻 `a[i] * left[i] * right[i]` 相加，就等價於把所有子陣列都數過一遍，但只需要兩次單調棧掃描。

