vector<long long> windowDP(const vector<int>& cost, int k) {
    int n = (int)cost.size();
    const long long kInf = (1LL << 60);
    vector<long long> dp(n, kInf);
    if (n == 0)
        return dp;

    dp[0] = 0;
    if (k <= 0)
        return dp;

    deque<int> dq;
    dq.push_back(0);
    for (int i = 1; i < n; i++) {
        while (!dq.empty() && dq.front() < i - k)
            dq.pop_front();

        if (!dq.empty())
            dp[i] = dp[dq.front()] + cost[i];

        while (!dq.empty() && dp[dq.back()] >= dp[i])
            dq.pop_back();
        if (dp[i] < kInf)
            dq.push_back(i);
    }
    return dp;
}
```
