long long countInversions(const vector<long long>& a) {
    vector<int> r = compress(a);
    int m = 0;
    for (int x : r)
        m = max(m, x);
    Fenwick fw(m);
    long long inv = 0;
    for (int i = 0; i < (int)a.size(); i++) {
        inv += i - fw.query(r[i]);  // Count previous elements > a[i]
        fw.add(r[i]);
    }
    return inv;
}
```
第 `i` 步以前，BIT 裡已經放了前面 `i` 個元素；其中 `fw.query(r[i])` 代表「小於等於目前值」的數量，所以兩者相減就是嚴格大於 `a[i]` 的個數。若改成從右往左掃描，也能等價地統計「右側比自己小」的元素數。

