// Single-source shortest path with priority_queue (lazy deletion)
vector<long long> dijkstra(int src, int n, const vector<vector<pair<int, int>>>& g) {
    const long long kInf = 1e18;
    vector<long long> dist(n, kInf);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    dist[src] = 0;
    pq.push({0, src});
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d > dist[u])
            continue;  // Lazy deletion: skip outdated entry
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});  // Push updated distance
            }
        }
    }
    return dist;
}
```

**懶惰刪除**是關鍵：`if (d > dist[u]) continue;` 這行讓已被更短路取代的堆項目直接被丟棄，不做多餘的鬆弛。邊權必須非負，否則已出堆的節點仍可能被更新，Dijkstra 不再正確。

```cpp
// Dijkstra with path reconstruction using parent array
pair<vector<long long>, vector<int>> dijkstraPath(int src, int n,
                                                  const vector<vector<pair<int, int>>>& g) {
    const long long kInf = 1e18;
    vector<long long> dist(n, kInf);
    vector<int> prev(n, -1);  // Parent in shortest path tree
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    dist[src] = 0;
    pq.push({0, src});
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d > dist[u])
            continue;
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                prev[v] = u;  // Record parent
                pq.push({dist[v], v});
            }
        }
    }
    return {dist, prev};
}

// Reconstruct path from src to dst
vector<int> getPath(const vector<int>& prev, int dst) {
    vector<int> path;
    for (int cur = dst; cur != -1; cur = prev[cur])
        path.push_back(cur);
    reverse(path.begin(), path.end());
    return path;
}
```

用 `prev[]` 陣列記錄每個節點在最短路樹中的父節點，從目的地往回追溯即可重建路徑。注意若 `dist[dst] == INF` 表示不可達，`prev[]` 追溯無意義。

