// Floyd-Warshall all-pairs shortest path
// Input: dist[i][j] initialized to edge weight, 0 for i==j, kInf if no direct edge
// After call: dist[i][j] = shortest path length between all pairs
const long long kInf = 1e18;
void floydWarshall(vector<vector<long long>>& dist, int n) {
    for (int k = 0; k < n; k++)
        for (int i = 0; i < n; i++) {
            if (dist[i][k] >= kInf)
                continue;  // Pruning: i cannot reach k
            for (int j = 0; j < n; j++)
                if (dist[k][j] < kInf)
                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);
        }
    // Post-check: if dist[i][i] < 0, a negative cycle is reachable from i
}

