void dfs(int v, int par) {
    dp[v][0] = 0;
    dp[v][1] = 1;  // Count node v itself
    for (int c : adj[v]) {
        if (c == par)
            continue;
        dfs(c, v);
        dp[v][1] += dp[c][0];                 // Select v: children unselected
        dp[v][0] += max(dp[c][0], dp[c][1]);  // Unselect v: children are free
    }
