// dp[v][j] = max value selecting exactly j nodes from subtree of v
// j = 0: select nothing; j >= 1: must include v itself in the count
vector<int> val;
vector<vector<int>> adj;
vector<vector<int>> dp;
vector<int> sz;
int cap;  // knapsack capacity

void dfs(int v, int par) {
    sz[v] = 1;
    dp[v].assign(cap + 1, 0);
    dp[v][1] = val[v];  // Select only node v
    for (int c : adj[v]) {
        if (c == par)
            continue;
        dfs(c, v);  // Merge child c into v; iterate j in reverse to stay in-place
        for (int j = min(sz[v], cap); j >= 0; j--) {
            for (int k = 1; k <= min(sz[c], cap - j); k++) {
                dp[v][j + k] = max(dp[v][j + k], dp[v][j] + dp[c][k]);
            }
        }
        sz[v] += sz[c];  // Update subtree size AFTER merging
    }
}

int treeKnapsack(int root, int n, int _K) {
    cap = _K;
    dp.assign(n + 1, {});
    sz.assign(n + 1, 0);
    dfs(root, -1);
    int ans = 0;
    for (int j = 0; j <= cap; j++)
        ans = max(ans, dp[root][j]);
    return ans;
}
```

