}
```

「洛谷 P2014 選課」問題要求：選某門課前必須先選其先修課（樹狀依賴）。做法是建立虛擬根節點 0，所有無先修課的課程連到 0，利用「選 j 個子樹節點時 v 必須被選（j≥1）」的約束直接套用樹上背包框架。

template_code:
// Tree Knapsack: select at most cap nodes to maximize total value (no dependency)
// dp[v][j] = max value selecting j nodes from subtree of v
// Complexity: O(n*cap)
vector<int> val;
vector<vector<int>> adj;
vector<vector<int>> dp;
vector<int> sz;
int cap;

void treeKnapsackDfs(int v, int par) {
    sz[v] = 1;
    dp[v].assign(cap + 1, 0);
    dp[v][1] = val[v];
    for (int c : adj[v]) {
        if (c == par)
            continue;
        treeKnapsackDfs(c, v);  // Use sz[v] as upper bound (BEFORE updating sz[v]) to keep O(nK)
        for (int j = min(sz[v], cap); j >= 0; j--)
            for (int k = 1; k <= min(sz[c], cap - j); k++)
                dp[v][j + k] = max(dp[v][j + k], dp[v][j] + dp[c][k]);
        sz[v] += sz[c];
    }
}

int solveTreeKnapsack(int root, int n, int _K) {
    cap = _K;
    dp.assign(n + 1, {});
    sz.assign(n + 1, 0);
    treeKnapsackDfs(root, -1);
    int ans = 0;
    for (int j = 0; j <= cap; j++)
        ans = max(ans, dp[root][j]);
    return ans;
}

