```cpp
struct ListNode {
    int val;
    ListNode* next;
};

// Returns the meeting node inside the cycle, or nullptr if no cycle
ListNode* detectCycleMeet(ListNode* head) {
    ListNode* slow = head;
    ListNode* fast = head;
    while (fast && fast->next) {  // Must check both before advancing
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast)
            return slow;  // Meeting point found inside cycle
    }
    return nullptr;  // No cycle: fast reached the end
}

bool hasCycle(ListNode* head) {
    return detectCycleMeet(head) != nullptr;
}
```

`while` 條件必須同時檢查 `fast != nullptr` 與 `fast->next != nullptr`，確保 `fast->next->next` 的存取安全。相遇點在環內某處，**不是**環入口，不可直接回傳為答案。

相遇後，令一個指針從 `head` 出發、另一個留在相遇點，兩者都以速度 1 前進，再次相遇處即為環入口：

```cpp
// Find the entry (start) node of the cycle; returns nullptr if no cycle
ListNode* findCycleEntry(ListNode* head) {
    ListNode* meet = detectCycleMeet(head);
    if (!meet)
        return nullptr;

    ListNode* p1 = head;  // Reset to head
    ListNode* p2 = meet;  // Stay at meeting point
    while (p1 != p2) {
        p1 = p1->next;  // Both move at speed 1
        p2 = p2->next;
    }
    return p1;  // Cycle entry node
}
```

數學保證：`a = kc - b`。`p1` 從 `head` 走 `a` 步到達入口；`p2` 從相遇點（入口後 `b` 步）走 `a = kc - b` 步，位置為 `b + kc - b = kc ≡ 0`（模 c），恰好回到入口。兩者同時到達，第一次相遇即為環入口。

奇偶長度下「中點」定義不同，需依是否要左中點選擇 `fast` 的起始位置：

```cpp
// Right-middle for even length (fast starts at head)
ListNode* findMiddle(ListNode* head) {
    ListNode *slow = head, *fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    return slow;
}

// Left-middle for even length (fast starts one step ahead)
ListNode* findLeftMiddle(ListNode* head) {
    ListNode *slow = head, *fast = head->next;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    return slow;
}

// Merge two sorted lists
ListNode* merge(ListNode* l1, ListNode* l2) {
    ListNode dummy(0);
    ListNode* cur = &dummy;
    while (l1 && l2) {
        if (l1->val <= l2->val) {
            cur->next = l1;
            l1 = l1->next;
        } else {
            cur->next = l2;
            l2 = l2->next;
        }
        cur = cur->next;
    }
    cur->next = l1 ? l1 : l2;
    return dummy.next;
}

// Merge sort on linked list using fast-slow split
ListNode* mergeSort(ListNode* head) {
    if (!head || !head->next)
        return head;
    ListNode* mid = findLeftMiddle(head);
    ListNode* right = mid->next;
    mid->next = nullptr;  // Split into two halves
    return merge(mergeSort(head), mergeSort(right));
}
```

歸併排序必須使用**左中點**（`fast` 從 `head->next` 出發），使長度為 2 的串列分割為 `[head]` 和 `[head->next]` 各一個，避免右中點時分割後左半仍是 `[head, head->next]`、右半為空而無限遞迴。

template_code:
// Floyd cycle detection + cycle entry finding
ListNode *slow = head, *fast = head;

// Phase 1: Detect cycle and find meeting point
while (fast && fast->next) {
    slow = slow->next;
    fast = fast->next->next;
    if (slow == fast)
        break;  // Meeting point found inside cycle
}

if (!fast || !fast->next) {
    // No cycle detected
} else {
    // Phase 2: Find cycle entry node
    slow = head;  // Reset one pointer to head
    while (slow != fast) {
        slow = slow->next;  // Both move at speed 1
        fast = fast->next;
    }
    // slow == fast == cycle entry node
}

deep_dive.body:
以「長度 k 的子陣列最大和」為例，視窗和 `sum` 隨指針滑動增量維護：

```cpp
long long maxSumFixed(const vector<int>& a, int k) {
    long long sum = 0, best = LLONG_MIN;
    for (int i = 0; i < (int)a.size(); i++) {
        sum += a[i];  // 1) enter a[i]
        if (i < k - 1)
            continue;           // window not full yet
        best = max(best, sum);  // 2) update with a full window
        sum -= a[i - k + 1];    // 3) leave the leftmost element
    }
    return best;
}
```

三步驟的順序不能亂：必須等視窗湊滿 `k` 個元素才更新答案，否則會把長度不足的前綴也算進去。

當統計量不是單純的和，而是「不同字母數」「某條件元素的個數」時，用一個計數器或頻次表搭配相同骨架。例如求每個長度 k 視窗內的母音數：

```cpp
vector<int> vowelsInWindows(const string& s, int k) {
    auto is_vowel = [](char c) { return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u'; };
    vector<int> res;
    int cnt = 0;
    for (int i = 0; i < (int)s.size(); i++) {
        cnt += is_vowel(s[i]);  // enter
        if (i < k - 1)
            continue;
        res.push_back(cnt);             // record
        cnt -= is_vowel(s[i - k + 1]);  // leave
    }
    return res;
}
```

只要「入」與「出」是對稱的可逆操作（加一/減一、insert/erase），這個模板就成立。

template_code:
// Fixed-length sliding window: enter -> update -> leave
long long fixedWindow(const vector<int>& a, int k) {
    long long sum = 0, best = LLONG_MIN;
    for (int i = 0; i < (int)a.size(); i++) {
        sum += a[i];  // enter a[i]
        if (i < k - 1)
            continue;           // wait until the window holds k items
        best = max(best, sum);  // window [i-k+1, i] is exactly length k
        sum -= a[i - k + 1];    // leave the leftmost item
    }
    return best;
}

deep_dive.body:
最基礎的歸併：誰小先放誰，某側走完後把另一側剩餘全部接上。

```cpp
vector<int> mergeSorted(const vector<int>& a, const vector<int>& b) {
    vector<int> res;
    res.reserve(a.size() + b.size());
    int i = 0, j = 0;
    while (i < (int)a.size() && j < (int)b.size()) {
        if (a[i] <= b[j])
            res.push_back(a[i++]);
        else
            res.push_back(b[j++]);
    }
    while (i < (int)a.size())
        res.push_back(a[i++]);
    while (j < (int)b.size())
        res.push_back(b[j++]);
    return res;
}
```

`a[i] <= b[j]` 用 `<=` 而非 `<` 可保持穩定性（相等時先取 a），在需要穩定歸併時很重要。

求兩有序陣列交集時，相等才同時記錄並雙雙前進；否則推進較小側：

```cpp
vector<int> intersect(const vector<int>& a, const vector<int>& b) {
    vector<int> res;
    int i = 0, j = 0;
    while (i < (int)a.size() && j < (int)b.size()) {
        if (a[i] == b[j]) {
            res.push_back(a[i]);
            i++;
            j++;
        } else if (a[i] < b[j])
            i++;
        else
            j++;
    }
    return res;
}
```

判斷 `s` 是否為 `t` 的子序列也是雙序列指針：`j` 掃 `t`，若 `t[j]==s[i]` 就 `i++`，最後看 `i` 是否走完 `s`。差別只在「不要求 t 有序，只要求順序匹配」。

template_code:
// Merge two sorted sequences in O(n+m)
vector<int> mergeSorted(const vector<int>& a, const vector<int>& b) {
    vector<int> res;
    res.reserve(a.size() + b.size());
    int i = 0, j = 0;
    while (i < (int)a.size() && j < (int)b.size())
        res.push_back(a[i] <= b[j] ? a[i++] : b[j++]);
    while (i < (int)a.size())
        res.push_back(a[i++]);
    while (j < (int)b.size())
        res.push_back(b[j++]);
    return res;
}

deep_dive.body:
以「最長連續相同字元段長度」為例：

```cpp
int longestRun(const string& s) {
    int n = s.size(), ans = 0, i = 0;
    while (i < n) {
        int j = i;
        while (j < n && s[j] == s[i])
            j++;                // extend the current group
        ans = max(ans, j - i);  // group is [i, j)
        i = j;                  // jump to next group's start
    }
    return ans;
}
```

不論段的定義是什麼（相同、遞增、奇偶交替……），都只要替換內層 while 的條件，外層永遠是 `i = j` 跳段，保證每個元素只被掃一次。

當「是否屬於同一段」取決於相鄰兩元素關係（如嚴格遞增、交替奇偶），內層條件比較 `s[j]` 與 `s[j-1]`：

```cpp
int longestAlternating(const vector<int>& a) {
    int n = a.size(), ans = 0, i = 0;
    while (i < n) {
        int j = i + 1;
        // same group while parity keeps alternating
        while (j < n && (a[j] % 2) != (a[j - 1] % 2))
            j++;
        ans = max(ans, j - i);
        i = j;  // next group starts where this broke
    }
    return ans;
}
```

注意內層從 `i+1` 開始（單一元素自成一段），跳出後 `i = j` 讓**斷點**成為下一段起點，而不是 `i = j+1`，否則會漏掉斷點元素。

template_code:
// Grouping loop: split a sequence into maximal qualifying segments
// Replace the inner condition to fit the segment definition.
int groupingLoop(const vector<int>& a) {
    int n = a.size(), ans = 0, i = 0;
    while (i < n) {
        int j = i + 1;
        while (j < n && /* a[j] belongs to the same group as a[j-1] */ a[j] > a[j - 1])
            j++;
        ans = max(ans, j - i);  // segment [i, j)
        i = j;                  // the break point becomes the next start
    }
    return ans;
}

deep_dive.body:
`m×n` 乘法表第 K 小：`cnt(x) = Σ min(x / i, n)`（第 i 列有幾個 `i·j <= x`）。對答案二分：

```cpp
int findKthNumber(int m, int n, int k) {
    auto count_less_equal = [m, n](long long x) {
        long long c = 0;
        for (int i = 1; i <= m; i++)
            c += min(x / i, (long long)n);
        return c;
    };
    int lo = 1, hi = m * n;
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (count_less_equal(mid) >= k)
            hi = mid;  // enough numbers <= mid, shrink
        else
            lo = mid + 1;
    }
    return lo;  // smallest x with count_less_equal(x) >= k
}
```

迴圈結束時 `lo` 即第 K 小。即使 `mid` 不在乘法表內，因 `cnt` 在真實值處才「跳級」，最終收斂到的 `lo` 必為表內真實值。

求所有數對絕對差中的第 K 小：排序後，`cnt(x)=` 差 `<= x` 的對數，用雙指針 O(n) 求得：

```cpp
int smallestDistancePair(vector<int>& a, int k) {
    sort(a.begin(), a.end());
    int n = a.size();
    auto count_pairs = [&a, n](int x) {
        int c = 0, l = 0;
        for (int r = 0; r < n; r++) {
            while (a[r] - a[l] > x)
                l++;     // keep diff within x
            c += r - l;  // pairs ending at r
        }
        return c;
    };
    int lo = 0, hi = a[n - 1] - a[0];
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (count_pairs(mid) >= k)
            hi = mid;
        else
            lo = mid + 1;
    }
    return lo;
}
```

這裡 `cnt` 本身是一個不定長滑動視窗：外層值域二分 × 內層雙指針，是「二分套計數」的經典組合。

template_code:
// Kth smallest by binary searching the value, using count(<= x) >= k
template <class Cnt>
long long kthSmallest(long long lo, long long hi, long long k, Cnt cnt) {
    while (lo < hi) {
        long long mid = lo + (hi - lo) / 2;
        if (cnt(mid) >= k)
            hi = mid;  // at least k values are <= mid
        else
            lo = mid + 1;
    }
    return lo;  // smallest value whose prefix count reaches k
}

deep_dive.body:
「把陣列分成 m 段使各段和的最大值最小」：`check(x)=` 以「段和不超過 x」貪心切，所需段數 `<= m` 即可行。可行性對 `x` 單調遞增，找最小可行 `x`：

```cpp
int splitArray(vector<int>& a, int m) {
    auto check = [&a, m](long long x) {
        int parts = 1;
        long long cur = 0;
        for (int v : a) {
            if (v > x)
                return false;  // a single element exceeds x
            if (cur + v > x) {
                parts++;
                cur = 0;
            }
            cur += v;
        }
        return parts <= m;  // feasible with <= m segments
    };
    long long lo = *max_element(a.begin(), a.end());
    long long hi = accumulate(a.begin(), a.end(), 0LL);
    while (lo < hi) {
        long long mid = lo + (hi - lo) / 2;
        if (check(mid))
            hi = mid;  // feasible -> try smaller max
        else
            lo = mid + 1;
    }
    return lo;
}
```

`lo` 取單一元素最大值（任何段至少裝得下最大元素），`hi` 取總和（全放一段）。

「在 n 個位置放 k 頭牛使任兩頭最近距離最大」：`check(x)=` 貪心從最左開始、每超過 `x` 才放一頭，能放 `>= k` 即可行。可行性對 `x` 單調遞減，找**最大**可行 `x`：

```cpp
int maxMinDistance(vector<int>& pos, int k) {
    sort(pos.begin(), pos.end());
    auto check = [&pos, k](int x) {
        int cnt = 1, last = pos[0];
        for (int p : pos)
            if (p - last >= x) {
                cnt++;
                last = p;
            }
        return cnt >= k;
    };
    int lo = 1, hi = pos.back() - pos.front(), ans = 0;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (check(mid)) {
            ans = mid;
            lo = mid + 1;
        }  // feasible -> try larger
        else
            hi = mid - 1;
    }
    return ans;
}
```

注意方向相反：最大化最小值時，可行就往**大**走（`lo = mid + 1`），用 `ans` 記錄最後一個可行解。

template_code:
// Minimize the maximum: find the smallest feasible x
template <class Check>
long long minimizeMax(long long lo, long long hi, Check feasible) {
    while (lo < hi) {
        long long mid = lo + (hi - lo) / 2;
        if (feasible(mid))
            hi = mid;  // feasible -> push the bound down
        else
            lo = mid + 1;
    }
    return lo;
}
// Maximize the minimum: mirror it (feasible -> lo = mid + 1, track ans).

deep_dive.body:
經典：含負數時不能用滑窗，改用前綴和 + 雜湊。

```cpp
int subarraySum(vector<int>& a, int k) {
    unordered_map<long long, int> seen{{0, 1}};  // empty prefix
    long long pre = 0;
    int cnt = 0;
    for (int v : a) {
        pre += v;
        cnt += seen.count(pre - k) ? seen[pre - k] : 0;  // need pre[l] = pre - k
        seen[pre]++;
    }
    return cnt;
}
```

初始放入 `{0:1}` 代表「空前綴」，否則會漏掉從頭開始就等於 k 的子陣列。

`S[i][j]` 為左上角到 `(i-1,j-1)` 的矩形和，建表與查詢都用容斥：

```cpp
// build: prefix has size (n+1) x (m+1), zero-padded
for (int i = 1; i <= n; i++)
    for (int j = 1; j <= m; j++)
        prefix[i][j] = a[i - 1][j - 1] + prefix[i - 1][j] + prefix[i][j - 1] - prefix[i - 1][j - 1];

// query rectangle [r1..r2] x [c1..c2] (0-indexed, inclusive):
auto rect_sum = [&prefix](int r1, int c1, int r2, int c2) {
    return prefix[r2 + 1][c2 + 1] - prefix[r1][c2 + 1] - prefix[r2 + 1][c1] + prefix[r1][c1];
};
```

建表的 `- S[i-1][j-1]` 與查詢的 `+ S[r1][c1]` 都是「多減一塊要補回」的容斥；padding 一圈 0 可免邊界特判。

template_code:
// 1D prefix sums: O(1) range queries after O(n) build
struct Prefix {
    vector<long long> pre;
    Prefix(const vector<int>& a) : pre(a.size() + 1, 0) {
        for (int i = 0; i < (int)a.size(); i++)
            pre[i + 1] = pre[i] + a[i];
    }
    long long sum(int l, int r) const {
        return pre[r + 1] - pre[l];
    }  // inclusive
};

deep_dive.body:
用單調棧求每個元素左右第一個更小者，左邊嚴格、右邊非嚴格避免重複：

```cpp
const long long kMod = 1e9 + 7;
int sumSubarrayMins(vector<int>& a) {
    int n = a.size();
    vector<int> L(n), R(n);  // boundaries where a[i] is the strict min
    stack<int> st;
    for (int i = 0; i < n; i++) {  // left: first index with a[left] < a[i]
        while (!st.empty() && a[st.top()] >= a[i])
            st.pop();
        L[i] = st.empty() ? -1 : st.top();
        st.push(i);
    }
    while (!st.empty())
        st.pop();
    for (int i = n - 1; i >= 0; i--) {  // right: first index with a[right] < a[i]
        while (!st.empty() && a[st.top()] > a[i])
            st.pop();
        R[i] = st.empty() ? n : st.top();
        st.push(i);
    }
    long long ans = 0;
    for (int i = 0; i < n; i++)
        ans = (ans + 1LL * a[i] * (i - L[i]) % kMod * (R[i] - i)) % kMod;
    return ans;
}
```

左用 `>=`（嚴格更小才停）、右用 `>`（遇相等不停），保證每個子陣列的最小值唯一歸給最左邊那個，避免重算。

「所有子陣列 (max − min) 之和」可拆成兩個獨立貢獻問題：

```cpp
// sum of maxima - sum of minima over all subarrays
long long subArrayRanges(vector<int>& a) {
    auto solve = [&a](bool want_max) {
        int n = a.size();
        long long s = 0;
        vector<int> left(n), right(n);
        stack<int> st;
        for (int i = 0; i < n; i++) {
            while (!st.empty() && (want_max ? a[st.top()] <= a[i] : a[st.top()] >= a[i]))
                st.pop();
            left[i] = st.empty() ? -1 : st.top();
            st.push(i);
        }
        st = {};
        for (int i = n - 1; i >= 0; i--) {
            while (!st.empty() && (want_max ? a[st.top()] < a[i] : a[st.top()] > a[i]))
                st.pop();
            right[i] = st.empty() ? n : st.top();
            st.push(i);
        }
        for (int i = 0; i < n; i++)
            s += 1LL * a[i] * (i - left[i]) * (right[i] - i);
        return s;
    };
    return solve(true) - solve(false);
}
```

「極差」「逆序貢獻」「最大值×長度」等都能用同一框架：先確定每元素的管轄區間，再乘上對應權重累加。

template_code:
// For each i, the range [L[i]+1, R[i]-1] where a[i] is the (leftmost) minimum.
// Left strict (>=), right non-strict (>) to avoid double counting equal values.
void minRanges(const vector<int>& a, vector<int>& L, vector<int>& R) {
    int n = a.size();
    L.assign(n, -1);
    R.assign(n, n);
    stack<int> st;
    for (int i = 0; i < n; i++) {
        while (!st.empty() && a[st.top()] >= a[i])
            st.pop();
        L[i] = st.empty() ? -1 : st.top();
        st.push(i);
    }
    st = stack<int>();
    for (int i = n - 1; i >= 0; i--) {
        while (!st.empty() && a[st.top()] > a[i])
            st.pop();
        R[i] = st.empty() ? n : st.top();
        st.push(i);
    }
}

deep_dive.body:
維護遞增棧，棧頂比當前大且還能刪就彈：

```cpp
string removeKdigits(string num, int k) {
    string st;
    for (char c : num) {
        while (!st.empty() && k > 0 && st.back() > c) {
            st.pop_back();
            k--;
        }
        st.push_back(c);
    }
    while (k > 0) {
        st.pop_back();
        k--;
    }  // still must remove from the tail
    int i = 0;
    while (i < (int)st.size() && st[i] == '0')
        i++;  // strip leading zeros
    string res = st.substr(i);
    return res.empty() ? "0" : res;
}
```

若掃完還有刪除額度（整體遞增的情況），從尾端補刪；最後去前導零。

每個字元恰留一個，要求字典序最小。多了兩個約束：當前字元已在棧中就跳過；彈棧前要確認被彈字元**後面還會再出現**。

```cpp
string smallestSubsequence(string s) {
    int cnt[26] = {0};
    bool in_stack[26] = {false};
    for (char c : s)
        cnt[c - 'a']++;
    string st;
    for (char c : s) {
        cnt[c - 'a']--;  // one fewer remaining
        if (in_stack[c - 'a'])
            continue;  // keep only one of each
        while (!st.empty() && st.back() > c && cnt[st.back() - 'a'] > 0) {
            in_stack[st.back() - 'a'] = false;  // safe to pop: appears later
            st.pop_back();
        }
        st.push_back(c);
        in_stack[c - 'a'] = true;
    }
    return st;
}
```

彈棧條件 `cnt[st.back()] > 0` 保證被刪字元之後還能補回，否則會丟失必須保留的字元。

template_code:
// Lexicographically smallest by removing k chars (monotone increasing stack)
string smallestAfterRemoval(const string& num, int k) {
    string st;
    for (char c : num) {
        while (!st.empty() && k > 0 && st.back() > c) {
            st.pop_back();
            k--;
        }
        st.push_back(c);
    }
    st.resize(st.size() - k);  // remove leftover from the tail
    return st;
}

deep_dive.body:
方向陣列 + 就地標記（把走過的陸地改成水）避免額外 visited：

```cpp
int dr[] = {-1, 1, 0, 0}, dc[] = {0, 0, -1, 1};
int dfs(vector<vector<char>>& g, int r, int c) {
    int rowCount = g.size(), col_count = g[0].size();
    if (r < 0 || r >= rowCount || c < 0 || c >= col_count || g[r][c] != '1')
        return 0;
    g[r][c] = '0';  // mark visited in place
    int area = 1;
    for (int k = 0; k < 4; k++)
        area += dfs(g, r + dr[k], c + dc[k]);
    return area;
}
int numIslands(vector<vector<char>>& g) {
    int cnt = 0;
    for (int r = 0; r < (int)g.size(); r++)
        for (int c = 0; c < (int)g[0].size(); c++)
            if (g[r][c] == '1') {
                dfs(g, r, c);
                cnt++;
            }
    return cnt;
}
```

大網格用遞迴 DFS 可能爆棧，改用顯式 stack 或 BFS 較安全。

所有源點同時入隊，按層擴散，第一次到達即最短：

```cpp
int orangesRotting(vector<vector<int>>& g) {
    int rowCount = g.size(), col_count = g[0].size(), fresh = 0;
    queue<pair<int, int>> q;
    for (int r = 0; r < rowCount; r++)
        for (int c = 0; c < col_count; c++) {
            if (g[r][c] == 2)
                q.push({r, c});  // all sources enqueued first
            else if (g[r][c] == 1)
                fresh++;
        }
    int dr[] = {-1, 1, 0, 0}, dc[] = {0, 0, -1, 1}, minutes = 0;
    while (!q.empty() && fresh) {
        int sz = q.size();
        while (sz--) {
            auto [r, c] = q.front();
            q.pop();
            for (int k = 0; k < 4; k++) {
                int nr = r + dr[k], nc = c + dc[k];
                if (nr < 0 || nr >= rowCount || nc < 0 || nc >= col_count || g[nr][nc] != 1)
                    continue;
                g[nr][nc] = 2;
                fresh--;
                q.push({nr, nc});
            }
        }
        minutes++;  // one layer = one minute
    }
    return fresh ? -1 : minutes;
}
```

每處理完一整層 `minutes++`，這就是 BFS「按邊數分層」的特性；多源只是初始把所有起點放進同一層。

template_code:
// Grid BFS shortest steps (unit edges) from a single source
int dr[] = {-1, 1, 0, 0}, dc[] = {0, 0, -1, 1};
int bfsGrid(vector<vector<int>>& g, int sr, int sc) {
    int rowCount = g.size(), col_count = g[0].size();
    vector<vector<int>> dist(rowCount, vector<int>(col_count, -1));
    queue<pair<int, int>> q;
    q.push({sr, sc});
    dist[sr][sc] = 0;
    while (!q.empty()) {
        auto [r, c] = q.front();
        q.pop();
        for (int k = 0; k < 4; k++) {
            int nr = r + dr[k], nc = c + dc[k];
            if (nr < 0 || nr >= rowCount || nc < 0 || nc >= col_count || g[nr][nc] == 0 ||
                dist[nr][nc] != -1)
                continue;
            dist[nr][nc] = dist[r][c] + 1;
            q.push({nr, nc});
        }
    }
    return dist[rowCount - 1][col_count - 1];
}

deep_dive.body:
統計每點入度，反覆移除入度 0 的點；最後 `onCycle` 為真者即在某個環上：

```cpp
vector<char> findCycleNodes(const vector<int>& next) {  // next[i] = i's out-edge
    int n = next.size();
    vector<int> indeg(n, 0);
    for (int i = 0; i < n; i++)
        indeg[next[i]]++;
    queue<int> q;
    for (int i = 0; i < n; i++)
        if (indeg[i] == 0)
            q.push(i);
    vector<char> on_cycle(n, 1);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        on_cycle[u] = 0;  // peeled off -> a tree node
        if (--indeg[next[u]] == 0)
            q.push(next[u]);
    }
    return on_cycle;  // remaining 1's lie on cycles
}
```

剝葉後仍留有入度的節點全部在環上；這比 DFS 找環更不易出錯，也方便接著做環上計算。

從某點出發，快指針一次兩步、慢指針一步，相遇後再繞一圈量環長：

```cpp
int cycleLength(const vector<int>& next, int start) {
    int slow = start, fast = start;
    do {
        slow = next[slow];
        fast = next[next[fast]];
    } while (slow != fast);  // meet inside the cycle
    int len = 0;
    do {
        fast = next[fast];
        len++;
    } while (fast != slow);
    return len;
}
```

函數圖一定有環，所以快慢指針必相遇；這常用於「能否回到自己／最大環長」這類題。

template_code:
// Mark cycle nodes of a functional graph (each node has one out-edge) by peeling.
vector<char> functionalGraphCycle(const vector<int>& next) {
    int n = next.size();
    vector<int> indeg(n, 0);
    for (int v : next)
        indeg[v]++;
    queue<int> q;
    for (int i = 0; i < n; i++)
        if (!indeg[i])
            q.push(i);
    vector<char> on_cycle(n, 1);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        on_cycle[u] = 0;
        if (--indeg[next[u]] == 0)
            q.push(next[u]);
    }
    return on_cycle;
}

deep_dive.body:
對每一位獨立統計有幾個數該位為 1，AND 的貢獻來自「兩數該位都是 1 的對數」：

```cpp
// sum over all pairs (i<j) of (a[i] & a[j])
long long pairAndSum(const vector<int>& a) {
    long long total = 0;
    for (int b = 0; b < 30; b++) {
        long long ones = 0;
        for (int x : a)
            if (x >> b & 1)
                ones++;
        total += (ones * (ones - 1) / 2) << b;  // comb(ones, 2) pairs contribute 2^b
    }
    return total;
}
```

XOR 之和則改成 `ones * (n - ones)`（一 0 一 1 的對才貢獻）。逐位獨立讓 O(n²) 變 O(n·30)。

常見的位元小工具：

```cpp
int popcount(unsigned x) {  // count set bits
    int c = 0;
    while (x) {
        x &= x - 1;
        c++;
    }  // drop the lowest set bit each step
    return c;
}
int lowbit(int x) {
    return x & -x;
}  // isolate the lowest set bit
bool isPow2(unsigned x) {
    return x && !(x & (x - 1));
}
// enumerate all submasks of m (descending):
// for (int s = m; s; s = (s - 1) & m) { /* use s */ }
```

C++20 可直接用 `std::popcount`、`std::countr_zero`；競賽常用 GCC 內建 `__builtin_popcount` / `__builtin_ctz`。

template_code:
// Per-bit decomposition: count contribution of each bit independently.
long long perBitSum(const vector<int>& a, int B = 30) {
    long long total = 0;
    for (int b = 0; b < B; b++) {
        long long ones = 0;
        for (int x : a)
            ones += (x >> b) & 1;
        // example: XOR-sum over all pairs uses ones * (n - ones) << b
        total += ones * ((long long)a.size() - ones) << b;
    }
    return total;
}

deep_dive.body:
插入每個數的二進位（高位在上），查詢時貪心走相反位：

```cpp
struct XorTrie {
    static const int B = 30;
    vector<array<int, 2>> ch{{{0, 0}}};  // node 0 is the root
    void insert(int x) {
        int u = 0;
        for (int b = B; b >= 0; b--) {
            int d = x >> b & 1;
            if (!ch[u][d]) {
                ch.push_back({0, 0});
                ch[u][d] = ch.size() - 1;
            }
            u = ch[u][d];
        }
    }
    int queryMax(int x) {  // max (x ^ y) over inserted y
        int u = 0, res = 0;
        for (int b = B; b >= 0; b--) {
            int d = x >> b & 1;
            if (ch[u][d ^ 1]) {
                res |= 1 << b;
                u = ch[u][d ^ 1];
            }  // go opposite
            else
                u = ch[u][d];
        }
        return res;
    }
};
```

每一位優先走「與 x 相反」的子（讓該位異或為 1），走不通才同向；高位優先保證結果最大。

若只需最大異或對，可用集合逐位試填，無需顯式 Trie：

```cpp
int findMaximumXOR(vector<int>& a) {
    int ans = 0, mask = 0;
    for (int b = 30; b >= 0; b--) {
        mask |= 1 << b;  // consider prefixes up to bit b
        unordered_set<int> pref;
        for (int x : a)
            pref.insert(x & mask);
        int want = ans | (1 << b);  // can we make this bit a 1?
        for (int p : pref)
            if (pref.count(want ^ p)) {
                ans = want;
                break;
            }  // two prefixes xor to 'want'
    }
    return ans;
}
```

每位假設答案該位能是 1（`want`），若存在兩前綴異或得到 `want` 就鎖定；這是「試填 + 雜湊」的代表。

template_code:
// 0-1 Trie for maximum XOR queries
struct XorTrie {
    static const int B = 30;
    vector<array<int, 2>> ch{{{0, 0}}};
    void insert(int x) {
        int u = 0;
        for (int b = B; b >= 0; b--) {
            int d = (x >> b) & 1;
            if (!ch[u][d]) {
                ch.push_back({0, 0});
                ch[u][d] = (int)ch.size() - 1;
            }
            u = ch[u][d];
        }
    }
    int queryMax(int x) {
        int u = 0, res = 0;
        for (int b = B; b >= 0; b--) {
            int d = (x >> b) & 1;
            if (ch[u][d ^ 1]) {
                res |= 1 << b;
                u = ch[u][d ^ 1];
            } else
                u = ch[u][d];
        }
        return res;
    }
};

deep_dive.body:
用費馬小定理求逆元，遞推 `inv_fact` 避免每次快速冪：

```cpp
const long long kMod = 1e9 + 7;
const int N = 1e6 + 5;
long long fact[N], inv_fact[N];
long long power(long long a, long long b, long long m) {
    long long r = 1;
    a %= m;
    for (; b; b >>= 1, a = a * a % m)
        if (b & 1)
            r = r * a % m;
    return r;
}
void initComb() {
    fact[0] = 1;
    for (int i = 1; i < N; i++)
        fact[i] = fact[i - 1] * i % kMod;
    inv_fact[N - 1] = power(fact[N - 1], kMod - 2, kMod);
    for (int i = N - 1; i > 0; i--)
        inv_fact[i - 1] = inv_fact[i] * i % kMod;
}
long long comb(int n, int r) {
    if (r < 0 || r > n)
        return 0;
    return fact[n] * inv_fact[r] % kMod * inv_fact[n - r] % kMod;
}
```

`inv_fact` 從大到小遞推（`inv_fact[i-1] = inv_fact[i]·i`）只需一次快速冪，整體 O(n)。

錯位排列（沒有元素在原位）用容斥：

```cpp
// D(n): permutations with no fixed point, via inclusion-exclusion
long long derangement(int n) {
    long long res = 0;
    for (int k = 0; k <= n; k++) {
        long long term = comb(n, k) * fact[n - k] % kMod;  // fix k positions
        res = (k & 1) ? (res - term + kMod) % kMod : (res + term) % kMod;
    }
    return res;  // = sum (-1)^k comb(n, k)(n-k)!
}
```

「至少 k 個滿足」的計數常先算「指定某 k 個都滿足、其餘任意」再容斥成「恰好」；符號隨容斥層數正負交替。

template_code:
// O(1) binomial coefficients modulo a prime after O(n) preprocessing.
const long long kMod = 1e9 + 7;
vector<long long> fact, inv_fact;
long long power(long long a, long long b) {
    long long r = 1;
    a %= kMod;
    for (; b; b >>= 1, a = a * a % kMod)
        if (b & 1)
            r = r * a % kMod;
    return r;
}
void initComb(int n) {
    fact.assign(n + 1, 1);
    inv_fact.assign(n + 1, 1);
    for (int i = 1; i <= n; i++)
        fact[i] = fact[i - 1] * i % kMod;
    inv_fact[n] = power(fact[n], kMod - 2);
    for (int i = n; i > 0; i--)
        inv_fact[i - 1] = inv_fact[i] * i % kMod;
}
long long comb(int n, int r) {
    if (r < 0 || r > n)
        return 0;
    return fact[n] * inv_fact[r] % kMod * inv_fact[n - r] % kMod;
}

deep_dive.body:
Nim 結論只需一行異或：

```cpp
bool firstPlayerWinsNim(const vector<int>& piles) {
    int x = 0;
    for (int p : piles)
        x ^= p;     // Nim-sum
    return x != 0;  // nonzero -> first player wins
}
```

直覺：異或非 0 時，先手總能取一步讓異或變 0（把對手丟進必敗態），反之先手怎麼動都會破壞全 0。

對「每次可取 1..m 顆」之類的取石子遊戲求 SG：

```cpp
// SG for a game where from a pile of size i you may remove any value in moves[]
vector<int> computeSG(int n, const vector<int>& moves) {
    vector<int> sg(n + 1, 0);
    for (int i = 1; i <= n; i++) {
        set<int> reachable;
        for (int m : moves)
            if (i - m >= 0)
                reachable.insert(sg[i - m]);
        int mex = 0;
        while (reachable.count(mex))
            mex++;  // smallest excluded value
        sg[i] = mex;
    }
    return sg;
}
// Combine independent games: overall losing iff XOR of their SG values == 0.
```

把局面拆成互不干擾的子遊戲，各自查 SG 後全部異或；結果為 0 即先手必敗。這就是 SG 定理的威力。

template_code:
// Grundy (SG) values for a subtraction game; combine subgames by XOR.
vector<int> grundy(int n, const vector<int>& moves) {
    vector<int> sg(n + 1, 0);
    for (int i = 1; i <= n; i++) {
        set<int> s;
        for (int m : moves)
            if (i >= m)
                s.insert(sg[i - m]);
        int mex = 0;
        while (s.count(mex))
            mex++;
        sg[i] = mex;
    }
    return sg;
}

deep_dive.body:
插入分隔符後對每個中心求半徑，利用對稱複用：

```cpp
vector<int> manacher(const string& s) {
    string t = "^";
    for (char c : s) {
        t += '#';
        t += c;
    }
    t += "#$";  // sentinels avoid bounds checks
    int n = t.size();
    vector<int> p(n, 0);
    int center = 0, right = 0;
    for (int i = 1; i < n - 1; i++) {
        if (i < right)
            p[i] = min(right - i, p[2 * center - i]);  // mirror reuse
        while (t[i + p[i] + 1] == t[i - p[i] - 1])
            p[i]++;  // expand
        if (i + p[i] > right) {
            center = i;
            right = i + p[i];
        }  // extend window
    }
    return p;  // p[i] = palindrome radius in t
}
```

`p[i]` 正好等於原串中以該位置為中心的最長回文**長度**（分隔符的巧妙之處）。

找最大的 `p[i]`，由 `t` 的下標換回原串區間：

```cpp
string longestPalindrome(const string& s) {
    if (s.empty())
        return "";
    vector<int> p = manacher(s);
    int best_len = 0, best_center = 0;
    for (int i = 1; i + 1 < (int)p.size(); i++)
        if (p[i] > best_len) {
            best_len = p[i];
            best_center = i;
        }
    int start = (best_center - best_len) / 2;  // map back to original index
    return s.substr(start, best_len);
}
```

原串起點 `= (center - radius) / 2`，長度即 `radius`；推導來自插入 `#` 後每個原字元下標翻倍的關係。

template_code:
// Manacher: p[i] is the palindrome radius around position i in the transformed
// string; it equals the length of the longest palindrome centered there in s.
vector<int> manacher(const string& s) {
    string t = "^";
    for (char c : s) {
        t += '#';
        t += c;
    }
    t += "#$";
    int n = t.size();
    vector<int> p(n, 0);
    for (int i = 1, center = 0, right = 0; i < n - 1; i++) {
        if (i < right)
            p[i] = min(right - i, p[2 * center - i]);
        while (t[i + p[i] + 1] == t[i - p[i] - 1])
            p[i]++;
        if (i + p[i] > right) {
            center = i;
            right = i + p[i];
        }
    }
    return p;
}

deep_dive.body:
把轉移補全為自動機，使匹配時無需顯式跳 fail：

```cpp
struct AhoCorasick {
    static const int K = 26;
    vector<array<int, K>> go{{}};  // node 0 = root, transitions
    vector<int> fail{0}, cnt{0};   // fail link, #patterns ending here
    void insert(const string& s) {
        int u = 0;
        for (char c : s) {
            int d = c - 'a';
            if (!go[u][d]) {
                go.push_back({});
                fail.push_back(0);
                cnt.push_back(0);
                go[u][d] = go.size() - 1;
            }
            u = go[u][d];
        }
        cnt[u]++;
    }
    void build() {
        queue<int> q;
        for (int c = 0; c < K; c++)
            if (go[0][c])
                q.push(go[0][c]);
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int c = 0; c < K; c++) {
                int v = go[u][c];
                if (v) {
                    fail[v] = go[fail[u]][c];
                    q.push(v);
                } else
                    go[u][c] = go[fail[u]][c];  // path-compress transition
            }
        }
    }
};
```

`else go[u][c] = go[fail[u]][c]` 是關鍵：不存在的邊直接指向 fail 的轉移，匹配時每步 O(1)、無需迴圈跳 fail。

沿自動機走，累計每個前綴節點沿 fail 鏈的命中數（可用拓撲序優化）：

```cpp
long long countMatches(AhoCorasick& ac, const string& text) {
    long long total = 0;
    int u = 0;
    for (char c : text) {
        u = ac.go[u][c - 'a'];              // O(1) transition
        for (int v = u; v; v = ac.fail[v])  // walk fail chain (or precompute)
            total += ac.cnt[v];
    }
    return total;
}
```

若命中很密集，沿 fail 鏈逐節點累加可能退化；可按 fail 樹的拓撲序把 `cnt` 累加到 fail 父節點，查詢變 O(1)。

template_code:
// Aho-Corasick: multi-pattern matching with BFS-built fail links.
struct AhoCorasick {
    static const int K = 26;
    vector<array<int, K>> go{{}};
    vector<int> fail{0}, cnt{0};
    void insert(const string& s) {
        int u = 0;
        for (char c : s) {
            int d = c - 'a';
            if (!go[u][d]) {
                go.push_back({});
                fail.push_back(0);
                cnt.push_back(0);
                go[u][d] = (int)go.size() - 1;
            }
            u = go[u][d];
        }
        cnt[u]++;
    }
    void build() {
        queue<int> q;
        for (int c = 0; c < K; c++)
            if (go[0][c])
                q.push(go[0][c]);
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int c = 0; c < K; c++) {
                int v = go[u][c];
                if (v) {
                    fail[v] = go[fail[u]][c];
                    q.push(v);
                } else
                    go[u][c] = go[fail[u]][c];
            }
        }
    }
};

deep_dive.body:
從右往左遞推 `nxt`，查詢時沿表跳：

```cpp
struct SubseqAutomaton {
    vector<array<int, 26>> nxt;  // nxt[i][c] = first index >= i with char c, or n
    int n;
    SubseqAutomaton(const string& s) : n(s.size()) {
        nxt.assign(n + 1, {});
        for (int c = 0; c < 26; c++)
            nxt[n][c] = n;  // n = "not found"
        for (int i = n - 1; i >= 0; i--) {
            nxt[i] = nxt[i + 1];
            nxt[i][s[i] - 'a'] = i;  // s[i] available from i itself
        }
    }
    bool isSubsequence(const string& t) const {
        int pos = 0;
        for (char c : t) {
            pos = nxt[pos][c - 'a'];
            if (pos == n)
                return false;  // char not found afterwards
            pos++;             // consume it, move past
        }
        return true;
    }
};
```

查詢時 `pos = nxt[pos][c]` 找到該字元位置後 `pos++` 往後推進；`pos == n` 代表後面再也沒有此字元，匹配失敗。

子序列自動機讓「不同子序列數」DP 一目了然：`f[i]` = 從位置 i 出發的不同子序列數，沿每個字元的首次出現轉移避免重複：

```cpp
// number of distinct non-empty subsequences (mod p), using first-occurrence
long long distinctSubseq(const string& s) {
    const long long kMod = 1e9 + 7;
    int n = s.size();
    SubseqAutomaton sa(s);
    vector<long long> f(n + 1, 0);
    f[n] = 1;  // empty subsequence (counted once)
    for (int i = n - 1; i >= 0; i--) {
        f[i] = 0;
        for (int c = 0; c < 26; c++)
            if (sa.nxt[i][c] < n)
                f[i] = (f[i] + f[sa.nxt[i][c] + 1]) % kMod;
        f[i] = (f[i] + 1) % kMod;  // the subsequence ending choices
    }
    return (f[0] - 1 + kMod) % kMod;  // exclude the empty one
}
```

只從「每個字元的首次出現」轉移，天然去重——這正是子序列自動機去除重複子序列的核心。

template_code:
// Subsequence automaton: nxt[i][c] = first index >= i holding char c (else n).
struct SubseqAutomaton {
    vector<array<int, 26>> nxt;
    int n;
    SubseqAutomaton(const string& s) : n(s.size()) {
        nxt.assign(n + 1, {});
        for (int c = 0; c < 26; c++)
            nxt[n][c] = n;
        for (int i = n - 1; i >= 0; i--) {
            nxt[i] = nxt[i + 1];
            nxt[i][s[i] - 'a'] = i;
        }
    }
    bool isSubsequence(const string& t) const {
        int pos = 0;
        for (char c : t) {
            pos = nxt[pos][c - 'a'];
            if (pos == n)
                return false;
            pos++;
        }
        return true;
    }
};

deep_dive.body:
`f[i]` = 前 i 字元的最少劃分次數，枚舉最後一段 `[j, i)`：

```cpp
int minCut(const string& s) {
    int n = s.size();
    // pal[j][i] = whether s[j..i-1] is a palindrome (precomputed)
    vector<vector<char>> pal(n, vector<char>(n + 1, 0));
    for (int j = n - 1; j >= 0; j--)
        for (int i = j + 1; i <= n; i++)
            pal[j][i] = (s[j] == s[i - 1]) && (i - j < 3 || pal[j + 1][i - 1]);
    vector<int> f(n + 1, INT_MAX);
    f[0] = 0;
    for (int i = 1; i <= n; i++)
        for (int j = 0; j < i; j++)
            if (pal[j][i] && f[j] != INT_MAX)
                f[i] = min(f[i], f[j] + 1);
    return f[n] - 1;  // cuts = segments - 1
}
```

「最後一段必須合法（回文）」是轉移的前提；先預處理合法性表，轉移就乾淨。

把陣列分成恰 k 段使各段和平方差等代價最小，`f[i][t]` = 前 i 個分成 t 段：

```cpp
// minimize total cost splitting a[0..n) into exactly k segments
long long partitionK(const vector<long long>& pre, int n, int k,
                     function<long long(int, int)> cost) {  // cost(j, i)=segment [j, i)
    const long long kInf = 1e18;
    vector<vector<long long>> f(n + 1, vector<long long>(k + 1, kInf));
    f[0][0] = 0;
    for (int i = 1; i <= n; i++)
        for (int t = 1; t <= min(i, k); t++)
            for (int j = t - 1; j < i; j++)
                if (f[j][t - 1] < kInf)
                    f[i][t] = min(f[i][t], f[j][t - 1] + cost(j, i));  // last seg [j, i)
    return f[n][k];
}
```

`cost(j, i)` 多半能用前綴和 O(1) 求得；若代價滿足四邊形不等式，可用決策單調性把這層 O(n) 降到 O(log n) 或更低。

template_code:
// Partition DP: f[i] = best over last segment [j, i)
// f[i] = min_{0<=j<i, valid(j, i)} f[j] + cost(j, i)
vector<long long> partitionDP(int n, function<bool(int, int)> valid,
                              function<long long(int, int)> cost) {
    const long long kInf = 1e18;
    vector<long long> f(n + 1, kInf);
    f[0] = 0;
    for (int i = 1; i <= n; i++)
        for (int j = 0; j < i; j++)
            if (f[j] < kInf && valid(j, i))
                f[i] = min(f[i], f[j] + cost(j, i));
    return f;
}

deep_dive.body:
狀態：`hold`（持股）、`sold`（剛賣出，次日冷凍）、`rest`（空倉可買）：

```cpp
int maxProfitCooldown(vector<int>& p) {
    int n = p.size();
    if (!n)
        return 0;
    int hold = -p[0], sold = 0, rest = 0;  // day 0
    for (int i = 1; i < n; i++) {
        int nhold = max(hold, rest - p[i]);  // keep, or buy from rest
        int nsold = hold + p[i];             // sell today
        int nrest = max(rest, sold);         // stay rest, or recover from sold
        hold = nhold;
        sold = nsold;
        rest = nrest;
    }
    return max(sold, rest);  // not holding at the end
}
```

每個轉移直接對應狀態圖的一條邊：買（rest→hold）、賣（hold→sold）、冷卻（sold→rest）、休息（自環）。

把「已用幾次交易」放進狀態，`buy[j]`/`sell[j]` 表示第 j 筆交易的持股／已賣最優：

```cpp
int maxProfitK(int k, vector<int>& p) {
    if (p.empty() || k == 0)
        return 0;
    vector<int> buy(k + 1, INT_MIN), sell(k + 1, 0);
    for (int price : p)
        for (int j = 1; j <= k; j++) {
            buy[j] = max(buy[j], sell[j - 1] - price);  // open j-th position
            sell[j] = max(sell[j], buy[j] + price);     // close j-th position
        }
    return sell[k];
}
```

交易次數本身就是狀態的一維；內層從 1 到 k 的遞推等價於 k 台狀態機串接。

template_code:
// State-machine DP skeleton: iterate items, update each state from reachable ones.
// Example states for stock-with-cooldown: hold / sold / rest.
int stateMachine(const vector<int>& p) {
    int hold = INT_MIN, sold = 0, rest = 0;
    for (int price : p) {
        int nhold = max(hold, rest - price);
        int nsold = hold + price;
        int nrest = max(rest, sold);
        hold = nhold;
        sold = nsold;
        rest = nrest;
    }
    return max(sold, rest);
}

deep_dive.body:
以「統計 [0, n] 中數位不含 4 的數」為例：

```cpp
string digits;
int dp[12][2];  // dp[pos][started]; valid only when !tight
int dfs(int pos, bool tight, bool started) {
    if (pos == (int)digits.size())
        return started ? 1 : 1;  // count this number
    if (!tight && dp[pos][started] != -1)
        return dp[pos][started];
    int hi = tight ? digits[pos] - '0' : 9;
    int res = 0;
    for (int d = 0; d <= hi; d++) {
        if (d == 4)
            continue;  // the digit constraint
        res += dfs(pos + 1, tight && (d == hi), started || d > 0);
    }
    if (!tight)
        dp[pos][started] = res;
    return res;
}
int countNoFour(int n) {
    digits = to_string(n);
    memset(dp, -1, sizeof dp);
    return dfs(0, true, false);
}
```

只有 `tight=false` 時才記憶化（此時剩餘位的答案與上界無關）；`tight=true` 的分支唯一、無需快取。

若條件涉及相鄰位（如相鄰數字差 ≥ 2），把上一位放進狀態，區間用差分：

```cpp
// answer for [L, R] = solve(R) - solve(L - 1)
// dp state adds 'prev' (last placed digit) when the rule couples adjacent digits:
//   dfs(pos, prev, tight, started)
// transition: for d in [0..hi], require started==false || abs(d - prev) >= 2
// memoize on dp[pos][prev] only when !tight && started.
long long countRange(long long L, long long R, function<long long(long long)> solve) {
    return solve(R) - solve(L - 1);  // classic prefix differencing
}
```

把「與相鄰位的約束」「目前數位和」「是否已出現某模式」等都放進狀態，是數位 DP 的擴展方向；前導零狀態 `started` 決定約束何時開始生效。

template_code:
// Digit DP template: count numbers in [0, n] with some digit property.
// States: pos, tight (still bounded by n), started (leading-zero handling).
// Memoize only when !tight (then the suffix is independent of the bound).
string g_digits;
long long g_dp[20][2];
long long digitDFS(int pos, bool tight, bool started) {
    if (pos == (int)g_digits.size())
        return 1;  // adjust to your counting
    if (!tight && g_dp[pos][started] != -1)
        return g_dp[pos][started];
    int hi = tight ? g_digits[pos] - '0' : 9;
    long long res = 0;
    for (int d = 0; d <= hi; d++) {
        // if (!allowed(d, started)) continue;          // place your constraint
        res += digitDFS(pos + 1, tight && d == hi, started || d > 0);
    }
    if (!tight)
        g_dp[pos][started] = res;
    return res;
}

deep_dive.body:
`f[l][r]` = 當前玩家在 `[l, r]` 的最大淨得分（自己減對手）：

```cpp
bool firstWins(vector<int>& a) {
    int n = a.size();
    vector<vector<int>> f(n, vector<int>(n, 0));
    for (int i = 0; i < n; i++)
        f[i][i] = a[i];  // one pile: take it all
    for (int len = 2; len <= n; len++)
        for (int l = 0; l + len - 1 < n; l++) {
            int r = l + len - 1;
            f[l][r] = max(a[l] - f[l + 1][r],   // take left
                          a[r] - f[l][r - 1]);  // take right
        }
    return f[0][n - 1] >= 0;  // first player not behind
}
```

「`a[l] - f[l+1][r]`」中減號的意義：剩下局面換對手當「當前玩家」，其淨得分要從我方視角扣除。

當只問勝負（非分數），用布林：存在一步讓對手必敗，則當前必勝：

```cpp
// can the current player force a win taking 1..3 stones, last taker wins?
unordered_map<int, int> memo;
bool canWin(int n) {
    if (n <= 0)
        return false;
    auto it = memo.find(n);
    if (it != memo.end())
        return it->second;
    bool win = false;
    for (int take = 1; take <= 3 && take <= n; take++)
        if (!canWin(n - take)) {
            win = true;
            break;
        }  // opponent loses next
    return memo[n] = win;
}
```

「存在一個後繼是對手必敗（`!canWin`）」⇒ 當前必勝；所有後繼皆對手必勝 ⇒ 當前必敗。這是必勝/必敗態 DP 的通用判據。

template_code:
// Game DP via relative score: f[state] = best (my score - opponent score)
// for the player to move. Interval version (take from either end):
int gameInterval(const vector<int>& a) {
    int n = a.size();
    vector<vector<int>> f(n, vector<int>(n, 0));
    for (int i = 0; i < n; i++)
        f[i][i] = a[i];
    for (int len = 2; len <= n; len++)
        for (int l = 0, r; (r = l + len - 1) < n; l++)
            f[l][r] = max(a[l] - f[l + 1][r], a[r] - f[l][r - 1]);
    return f[0][n - 1];  // >= 0 means the first player does not lose
}

deep_dive.body:
直線上每步以機率前進，求到終點期望步數，從終態倒推：

```cpp
// expected number of dice tosses to go from 0 to >= n, die is 1..6 uniform
double expectedTosses(int n) {
    vector<double> expected(n + 7, 0.0);  // expected[i] = expected tosses from i
    for (int i = n - 1; i >= 0; i--) {
        double e = 1.0;  // this toss counts as 1
        for (int f = 1; f <= 6; f++)
            e += (i + f >= n ? 0.0 : expected[i + f]) / 6.0;
        expected[i] = e;
    }
    return expected[0];
}
```

終態 `E[>=n]=0`，每個狀態的期望 = 1（本次操作）+ 各後繼期望的加權平均；逆向遞推自然滿足依賴順序。

「抽卡集齊 n 種的期望次數」（贈券收集）用線性性直接加總各階段期望：

```cpp
// coupon collector: expected draws to collect all n distinct types
double couponCollector(int n) {
    double exp = 0.0;
    for (int k = 1; k <= n; k++)
        exp += (double)n / k;  // when k-1 owned, P(new)= (n-k+1)/n
    return exp;                // sum of geometric expectations
}
```

把「集滿」拆成 n 個獨立階段，「已有 k−1 種、抽到第 k 種新卡」服從幾何分布，期望 `n/(n-k+1)`；線性性允許直接相加，無需處理聯合分布。

template_code:
// Backward expectation DP: expected[goal] = 0, then expected[s] = cost + sum p * expected[next].
// Example: expected steps with uniform 1..6 transitions on a line.
double expectedSteps(int n) {
    vector<double> expected(n + 7, 0.0);
    for (int i = n - 1; i >= 0; i--) {
        double e = 1.0;
        for (int f = 1; f <= 6; f++)
            e += (i + f >= n ? 0.0 : expected[i + f]) / 6.0;
        expected[i] = e;
    }
    return expected[0];
}

deep_dive.body:
讓總等待時間最小，應按服務時間升序；交換論證可證相鄰逆序對交換會變差：

```cpp
long long minTotalWait(vector<int>& t) {
    sort(t.begin(), t.end());  // shortest job first
    long long pre = 0, total = 0;
    for (int x : t) {
        total += pre;
        pre += x;
    }  // each later job waits for all earlier
    return total;
}
```

若存在相鄰兩人服務時間 `a > b` 卻 a 在前，交換他們會減少總等待——故最優解中必為升序，貪心正確。

把數字拼成最小，需自訂比較子 `a+b < b+a`（字串拼接比較）：

```cpp
string smallestConcat(vector<int>& nums) {
    vector<string> s;
    for (int x : nums)
        s.push_back(to_string(x));
    sort(s.begin(), s.end(), [](const string& a, const string& b) {
        return a + b < b + a;  // a should precede b
    });
    string res;
    for (auto& x : s)
        res += x;
    return res;
}
```

這個比較子滿足全序（可遞移），交換論證保證排序後拼接最優；最大數版本把 `<` 改成 `>`。

template_code:
// Greedy by sorting key, then one pass. Prove with an exchange argument.
long long greedyScan(vector<int>& a) {
    sort(a.begin(), a.end());
    long long pre = 0, total = 0;
    for (int x : a) {
        total += pre;
        pre += x;
    }
    return total;
}

deep_dive.body:
每個任務有截止期與利潤，每單位時間做一個，最大化總利潤：

```cpp
int maxProfitJobs(vector<pair<int, int>>& jobs) {         // {deadline, profit}
    sort(jobs.begin(), jobs.end());                       // by deadline ascending
    priority_queue<int, vector<int>, greater<int>> done;  // min-heap of chosen profits
    for (auto& [d, p] : jobs) {
        done.push(p);
        if ((int)done.size() > d)
            done.pop();  // too many by this deadline: drop worst
    }
    int total = 0;
    while (!done.empty()) {
        total += done.top();
        done.pop();
    }
    return total;
}
```

到截止 d 為止最多做 d 個任務；超額時彈出利潤最小者「反悔」，保證留下的永遠是利潤最大的可行子集。

路上經過加油站把可加油量存進堆，油不夠時回頭「加」之前最大的那桶：

```cpp
int minRefuel(int target, int start_fuel, vector<vector<int>>& st) {
    priority_queue<int> pq;  // fuel available at passed stations
    int fuel = start_fuel, refuels = 0, i = 0, n = st.size();
    int pos = 0;
    while (fuel < target) {
        while (i < n && st[i][0] <= fuel)
            pq.push(st[i++][1]);  // reachable stations
        if (pq.empty())
            return -1;  // cannot reach target
        fuel += pq.top();
        pq.pop();  // regret: take the biggest tank now
        refuels++;
    }
    return refuels;
}
```

不預先決定在哪加油，而是「先開到沒油，再回頭挑之前能加的最大一桶」，等價於最少加油次數。

template_code:
// Regret greedy: keep chosen items in a heap; replace the worst when overfull.
int regretSchedule(vector<pair<int, int>>& jobs) {  // {deadline, profit}
    sort(jobs.begin(), jobs.end());
    priority_queue<int, vector<int>, greater<int>> heap;  // min-heap of profits
    for (auto& [d, p] : jobs) {
        heap.push(p);
        if ((int)heap.size() > d)
            heap.pop();  // drop the least profitable
    }
    int total = 0;
    while (!heap.empty()) {
        total += heap.top();
        heap.pop();
    }
    return total;
}

deep_dive.body:
在保留每種字元至少需求量下，貪心組出字典序最小結果（示意：從計數構造最小排列且滿足某約束）：

```cpp
// Build the lexicographically smallest string using counts cnt[26].
// Place the smallest usable char whose use still leaves a feasible suffix.
string smallestFromCounts(int cnt[26], int total, function<bool(int, int*)> feasible) {
    string res;
    for (int pos = 0; pos < total; pos++) {
        for (int c = 0; c < 26; c++) {
            if (!cnt[c])
                continue;
            cnt[c]--;
            if (feasible(pos + 1, cnt)) {
                res += char('a' + c);
                break;
            }          // keep choice
            cnt[c]++;  // revert, try next char
        }
    }
    return res;
}
```

每位從最小字元開始試，`feasible` 確認用掉它後剩餘仍可完成；不可行就還原計數換下一個字元。

「能刪就刪」型字典序最小（如移除 k 位）用單調棧最直接：

```cpp
string smallestAfterRemoveK(const string& s, int k) {
    string st;
    for (char c : s) {
        while (!st.empty() && k > 0 && st.back() > c) {
            st.pop_back();
            k--;
        }
        st.push_back(c);  // greedily keep small prefix
    }
    st.resize(st.size() - k);  // remove leftover from tail
    return st;
}
```

當棧頂比當前字元大且還能刪，就彈掉它讓高位變小——這正是「逐位取最小且保證可行」在棧上的實現。

template_code:
// Lexicographic greedy: at each position take the smallest feasible char.
string lexSmallest(int n, function<bool(int, char)> canPlace) {
    string res;
    for (int i = 0; i < n; i++)
        for (char c = 'a'; c <= 'z'; c++)
            if (canPlace(i, c)) {
                res += c;
                break;
            }  // smallest that keeps a valid suffix
    return res;
}

deep_dive.body:
把 `1..n` 重排，使相鄰差或首尾和符合要求，常用首尾配對：

```cpp
// arrange 1..n so adjacent pairs from both ends sum constantly (zigzag pairing)
vector<int> pairConstruct(int n) {
    vector<int> res;
    int lo = 1, hi = n;
    while (lo <= hi) {
        res.push_back(lo++);
        if (lo <= hi)
            res.push_back(hi--);  // interleave small and large
    }
    return res;  // 1, n, 2, n-1, ...
}
```

「最小配最大」是構造題的常見招式，能讓和或差呈現規律；正確性由配對的對稱性直接保證。

許多構造先用不變量判定有無解，再給法則。例如把 `n` 拆成若干不同正整數之和的最大個數：

```cpp
// max count of distinct positive integers summing to n: greedily 1, 2, 3, ...
vector<int> maxDistinctParts(int n) {
    vector<int> res;
    int cur = 1;
    while (n - cur >= cur + 1) {
        res.push_back(cur);
        n -= cur;
        cur++;
    }
    res.push_back(n);  // dump the remainder into the last term
    return res;
}
```

貪心地用 `1,2,3,...` 累加，最後把剩餘塞進最大一項——保證互不相同且個數最多；這是「先找單調規律再構造」的典型。

template_code:
// Construction has no single template; a frequent device is two-pointer pairing
// (smallest with largest) to enforce a regular sum/difference structure.
vector<int> pairConstruct(int n) {
    vector<int> res;
    int lo = 1, hi = n;
    while (lo <= hi) {
        res.push_back(lo++);
        if (lo <= hi)
            res.push_back(hi--);
    }
    return res;
}

deep_dive.body:
每個遞迴節點本身就是一個合法子集：

```cpp
void dfs(int start, vector<int>& a, vector<int>& path, vector<vector<int>>& res) {
    res.push_back(path);  // record current subset
    for (int i = start; i < (int)a.size(); i++) {
        path.push_back(a[i]);      // choose a[i]
        dfs(i + 1, a, path, res);  // only pick from i+1 onward
        path.pop_back();           // undo
    }
}
vector<vector<int>> subsets(vector<int>& a) {
    vector<vector<int>> res;
    vector<int> path;
    dfs(0, a, path, res);
    return res;
}
```

`i + 1` 確保元素按序、不回頭，自動去除排列順序造成的重複。

先排序，同一層跳過相同元素：

```cpp
void dfsUnique(int start, vector<int>& a, vector<int>& path, vector<vector<int>>& res) {
    res.push_back(path);
    for (int i = start; i < (int)a.size(); i++) {
        if (i > start && a[i] == a[i - 1])
            continue;  // skip duplicate at this level
        path.push_back(a[i]);
        dfsUnique(i + 1, a, path, res);
        path.pop_back();
    }
}
```

`i > start`（而非 `i > 0`）是關鍵：只跳過「同一層」的重複，仍允許同一元素值在不同深度被選入。

template_code:
// Subset enumeration via start index (no duplicates among element orderings).
void subsetsDFS(int start, vector<int>& a, vector<int>& path, vector<vector<int>>& res) {
    res.push_back(path);
    for (int i = start; i < (int)a.size(); i++) {
        path.push_back(a[i]);
        subsetsDFS(i + 1, a, path, res);
        path.pop_back();
    }
}

deep_dive.body:
路徑滿即記錄，否則枚舉所有未用元素：

```cpp
void dfs(vector<int>& a, vector<char>& used, vector<int>& path, vector<vector<int>>& res) {
    if (path.size() == a.size()) {
        res.push_back(path);
        return;
    }
    for (int i = 0; i < (int)a.size(); i++) {
        if (used[i])
            continue;
        used[i] = 1;
        path.push_back(a[i]);     // choose
        dfs(a, used, path, res);  // recurse
        path.pop_back();
        used[i] = 0;  // undo
    }
}
```

每層從 0 開始掃，靠 `used` 跳過已選；這保證枚舉的是「順序」而非「組合」。

先排序，再用 `!used[i-1]` 同層去重：

```cpp
void dfsUnique(vector<int>& a, vector<char>& used, vector<int>& path, vector<vector<int>>& res) {
    if (path.size() == a.size()) {
        res.push_back(path);
        return;
    }
    for (int i = 0; i < (int)a.size(); i++) {
        if (used[i])
            continue;
        if (i > 0 && a[i] == a[i - 1] && !used[i - 1])
            continue;  // dup at same level
        used[i] = 1;
        path.push_back(a[i]);
        dfsUnique(a, used, path, res);
        path.pop_back();
        used[i] = 0;
    }
}
```

`!used[i-1]`：前一個相同元素已回溯（本層用過），故此重複者跳過；若改成 `used[i-1]` 則會錯誤去重、漏掉合法排列。

template_code:
// Permutations with used[] marking; sort + !used[i-1] to dedup equal elements.
void permuteDFS(vector<int>& a, vector<char>& used, vector<int>& path, vector<vector<int>>& res) {
    if (path.size() == a.size()) {
        res.push_back(path);
        return;
    }
    for (int i = 0; i < (int)a.size(); i++) {
        if (used[i])
            continue;
        if (i > 0 && a[i] == a[i - 1] && !used[i - 1])
            continue;
        used[i] = 1;
        path.push_back(a[i]);
        permuteDFS(a, used, path, res);
        path.pop_back();
        used[i] = 0;
    }
}

deep_dive.body:
選 k 個數，用「剩餘不足就回退」剪枝：

```cpp
void dfs(int start, int n, int k, vector<int>& path, vector<vector<int>>& res) {
    if ((int)path.size() == k) {
        res.push_back(path);
        return;
    }
    int need = k - path.size();
    // prune: not enough numbers left in [start, n] to fill 'need'
    for (int i = start; i <= n - need + 1; i++) {
        path.push_back(i);
        dfs(i + 1, n, k, path, res);
        path.pop_back();
    }
}
```

迴圈上界 `n - need + 1` 就是數量剪枝：再往後起點會湊不滿 k 個，直接不進入。

同一元素可重複選時，遞迴傳 `i`（不是 `i+1`）；排序後用和剪枝：

```cpp
void dfs(int start, vector<int>& a, int target, vector<int>& path, vector<vector<int>>& res) {
    if (target == 0) {
        res.push_back(path);
        return;
    }
    for (int i = start; i < (int)a.size(); i++) {
        if (a[i] > target)
            break;  // sorted: no larger one can fit either
        path.push_back(a[i]);
        dfs(i, a, target - a[i], path, res);  // i (not i+1): reuse allowed
        path.pop_back();
    }
}
```

`dfs(i, ...)` 允許重複使用當前元素；先排序後 `a[i] > target` 即可 `break`，省去所有更大元素的分支。

template_code:
// Combinations of size k from 1..n, with the "not enough left" pruning.
void combine(int start, int n, int k, vector<int>& path, vector<vector<int>>& res) {
    if ((int)path.size() == k) {
        res.push_back(path);
        return;
    }
    int need = k - (int)path.size();
    for (int i = start; i <= n - need + 1; i++) {
        path.push_back(i);
        combine(i + 1, n, k, path, res);
        path.pop_back();
    }
}

deep_dive.body:
用三個布林集合維護列與兩對角線的佔用，放置 O(1) 檢查：

```cpp
int total = 0, n;
vector<char> col, diag, anti;  // occupied columns / diagonals
void place(int r) {
    if (r == n) {
        total++;
        return;
    }
    for (int c = 0; c < n; c++) {
        int d = r + c, a = r - c + n;  // diagonal indices
        if (col[c] || diag[d] || anti[a])
            continue;  // feasibility prune
        col[c] = diag[d] = anti[a] = 1;
        place(r + 1);
        col[c] = diag[d] = anti[a] = 0;  // undo
    }
}
```

把「同列／同對角衝突」做成 O(1) 查表的可行性剪枝；還可只枚舉第一列的前半並利用左右對稱把答案 ×2。

在「最少分組／最小代價」型爆搜中，已超過當前最優就回退，並優先放難安置的元素：

```cpp
int best;
// assign items to groups, prune when used groups already >= best
void dfs(int idx, int groups_used, vector<int>& group_load, const vector<int>& items, int cap) {
    if (groups_used >= best)
        return;  // optimality prune
    if (idx == (int)items.size()) {
        best = min(best, groups_used);
        return;
    }
    for (int g = 0; g < groups_used; g++)
        if (group_load[g] + items[idx] <= cap) {
            group_load[g] += items[idx];
            dfs(idx + 1, groups_used, group_load, items, cap);
            group_load[g] -= items[idx];
        }
    group_load[groups_used] += items[idx];  // open a new group
    dfs(idx + 1, groups_used + 1, group_load, items, cap);
    group_load[groups_used] -= items[idx];
}
```

先把 `items` 由大到小排序（搜索順序優化）能更早撐爆容量、更快觸發剪枝；`groupsUsed >= best` 是最優性剪枝。

template_code:
// Pruned backtracking template: feasibility + optimality pruning.
int best;
void dfsPruned(int idx, int cost, /* state */ const vector<int>& a) {
    if (cost >= best)
        return;  // optimality prune
    if (idx == (int)a.size()) {
        best = min(best, cost);
        return;
    }
    // try choices ordered by "most constrained first" for earlier pruning
    // for (each feasible choice) { apply; dfsPruned(idx+1, cost+delta, a); undo; }
}

deep_dive.body:
Dinic 主體：BFS 分層，DFS 沿層推流並更新反向邊：

```cpp
struct Dinic {
    struct Edge {
        int to, rev;
        long long cap;
    };
    vector<vector<Edge>> g;
    vector<int> level, it;
    Dinic(int n) : g(n), level(n), it(n) {}
    void addEdge(int u, int v, long long c) {
        g[u].push_back({v, (int)g[v].size(), c});
        g[v].push_back({u, (int)g[u].size() - 1, 0});  // reverse edge
    }
    bool bfs(int s, int t) {
        fill(level.begin(), level.end(), -1);
        queue<int> q;
        q.push(s);
        level[s] = 0;
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (auto& e : g[u])
                if (e.cap > 0 && level[e.to] < 0) {
                    level[e.to] = level[u] + 1;
                    q.push(e.to);
                }
        }
        return level[t] >= 0;
    }
    long long dfs(int u, int t, long long f) {
        if (u == t)
            return f;
        for (int& i = it[u]; i < (int)g[u].size(); i++) {
            Edge& e = g[u][i];
            if (e.cap > 0 && level[e.to] == level[u] + 1) {
                long long d = dfs(e.to, t, min(f, e.cap));
                if (d > 0) {
                    e.cap -= d;
                    g[e.to][e.rev].cap += d;
                    return d;
                }
            }
        }
        return 0;
    }
    long long maxflow(int s, int t) {
        long long flow = 0;
        while (bfs(s, t)) {
            fill(it.begin(), it.end(), 0);
            while (long long f = dfs(s, t, LLONG_MAX))
                flow += f;
        }
        return flow;
    }
};
```

`for (int& i = it[u]; ...)` 用引用實現當前弧優化：已確定無用的邊不再重訪，是 Dinic 達標複雜度的核心。

反向邊讓算法能「反悔」先前推送的流，避免貪心走錯路卡死：

```cpp
// When we push d units along edge u->v:
//   e.cap     -= d;            // forward residual decreases
//   g[v][e.rev].cap += d;      // reverse residual increases, enabling cancellation
// A later augmenting path can traverse the reverse edge to redirect earlier flow.
```

沒有反向邊，一旦某條增廣選擇不是全域最優就無法修正，會得到偏小的流；反向邊把「重新分配」內建進殘量網路。

template_code:
// Dinic max flow (see topic page for the full struct). Usage:
//   Dinic din(n);
//   din.addEdge(u, v, cap);   // for each directed edge
//   long long F = din.maxflow(s, t);
// Each addEdge also inserts a reverse edge of capacity 0 to allow cancellation.

deep_dive.body:
最大流後，殘量網路上從 s 可達的點集即 S 側，跨越到不可達點的滿流邊即割邊：

```cpp
// after din.maxflow(s, t), find the S-side of the min cut
vector<char> minCutSide(Dinic& din, int s, int n) {
    vector<char> side(n, 0);
    queue<int> q;
    q.push(s);
    side[s] = 1;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (auto& e : din.g[u])
            if (e.cap > 0 && !side[e.to]) {
                side[e.to] = 1;
                q.push(e.to);
            }
    }
    return side;  // side[v]=1 -> v on S side
}
```

只沿「仍有殘量」的邊走；走不到的點屬 T 側。一條 `side[u]=1, side[v]=0` 的原始邊即割邊。

選一些點，選了某點就必須選其後繼，最大化點權和——轉成最小割：

```cpp
// Max-weight closure: source -> positive nodes (cap = weight).
// Negative nodes -> sink (cap = -weight), dependency u->v has cap kInf.
// Answer = (sum of positive weights) - maxflow(s, t).
void buildClosure(Dinic& din, int s, int t, const vector<int>& w,
                  const vector<pair<int, int>>& deps) {
    long long kInf = 1e18;
    for (int i = 0; i < (int)w.size(); i++) {
        if (w[i] > 0)
            din.addEdge(s, i, w[i]);
        else if (w[i] < 0)
            din.addEdge(i, t, -w[i]);
    }
    for (auto& [u, v] : deps)
        din.addEdge(u, v, kInf);  // must-take dependency
}
```

依賴邊容量設 `INF` 表示「絕不切斷」，強制閉合性；答案 = 正權總和 − 最小割（= 最大流）。

template_code:
// Min-cut value = max-flow value. Recover the S-side by BFS on the residual graph.
vector<char> recoverMinCut(Dinic& din, int s, int n) {
    vector<char> side(n, 0);
    queue<int> q;
    q.push(s);
    side[s] = 1;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (auto& e : din.g[u])
            if (e.cap > 0 && !side[e.to]) {
                side[e.to] = 1;
                q.push(e.to);
            }
    }
    return side;
}

deep_dive.body:
對每個左點 DFS 找增廣路，`matchR[r]` 記右點當前匹配的左點：

```cpp
vector<vector<int>> adj;  // adj[u] = right nodes adjacent to left u
vector<int> match_r;      // match_r[r] = matched left node, or -1
vector<char> vis;
bool augment(int u) {
    for (int v : adj[u]) {
        if (vis[v])
            continue;
        vis[v] = 1;
        if (match_r[v] == -1 || augment(match_r[v])) {  // v free or its match can move
            match_r[v] = u;
            return true;
        }
    }
    return false;
}
int hungarian(int n_left, int n_right) {
    match_r.assign(n_right, -1);
    int res = 0;
    for (int u = 0; u < n_left; u++) {
        vis.assign(n_right, 0);
        if (augment(u))
            res++;  // found an augmenting path for u
    }
    return res;
}
```

`augment(matchR[v])` 嘗試把佔用 v 的左點「讓位」到別處，這就是增廣路翻轉；每成功一次匹配數 +1。

最大匹配連結多個經典量，建模時直接套用：

```cpp
// Bipartite identities (no code needed, just the relations):
// max matching                = M
// minimum vertex cover        = M            (Konig's theorem)
// maximum independent set     = V - M
// DAG minimum path cover      = V - (max matching after node-splitting)
```

很多「最少選幾個覆蓋所有邊」「最多選互不衝突的點」「用最少鏈覆蓋 DAG」的題，本質都是先求最大匹配再套定理。

template_code:
// Hungarian algorithm (Kuhn) for maximum bipartite matching.
vector<vector<int>> adj;  // adj[u] = right neighbors of left node u
vector<int> match_r;      // match_r[v] = left node matched to right v, or -1
vector<char> vis;
bool augment(int u) {
    for (int v : adj[u]) {
        if (vis[v])
            continue;
        vis[v] = 1;
        if (match_r[v] == -1 || augment(match_r[v])) {
            match_r[v] = u;
            return true;
        }
    }
    return false;
}
int maxMatching(int n_left, int n_right) {
    match_r.assign(n_right, -1);
    int res = 0;
    for (int u = 0; u < n_left; u++) {
        vis.assign(n_right, 0);
        res += augment(u);
    }
    return res;
}
